/**
 * 获取学习库列表
 */
export async function GET(request: NextRequest) {
  try {
    const authHeader = request.headers.get('authorization');
    if (!authHeader?.startsWith('Bearer ')) {
      return NextResponse.json({ error: '未登录' }, { status: 401 });
    }

    const token = authHeader.split(' ')[1];
    const decoded = jwt.verify(token, JWT_SECRET) as { userId: string };

    const { searchParams } = new URL(request.url);
    const status = searchParams.get('status');
    const limit = parseInt(searchParams.get('limit') || '20');

    const client = getSupabaseClient();

    let query = client
      .from('learning_library')
      .select('*', { count: 'exact' })
      .eq('user_id', decoded.userId)
      .order('created_at', { ascending: false })
      .limit(limit);

    if (status) {
      query = query.eq('analysis_status', status);
    }

    const { data: learnings, count, error } = await query;

    if (error) {
      throw new Error(`查询失败: ${error.message}`);
    }

    // 统计分析状态
    const { data: stats } = await client
      .from('learning_library')
      .select('analysis_status')
      .eq('user_id', decoded.userId);

    const statusStats: Record<string, number> = {};
    (stats || []).forEach((l: any) => {
      const key = l.analysis_status as string;
      statusStats[key] = (statusStats[key] || 0) + 1;
    });

    return NextResponse.json({
      learnings,
      total: (learnings as any[])?.length || 0,
      stats: statusStats,
    });
  } catch (error) {
    console.error('获取学习库列表错误:', error);

    if (error instanceof jwt.JsonWebTokenError) {
      return NextResponse.json({ error: '登录已过期' }, { status: 401 });
    }

    return NextResponse.json(
      { error: error instanceof Error ? error.message : '查询失败' },
      { status: 500 }
    );
  }
}

/**
 * 删除学习记录
 */
export async function DELETE(request: NextRequest) {
  try {
    const authHeader = request.headers.get('authorization');
    if (!authHeader?.startsWith('Bearer ')) {
      return NextResponse.json({ error: '未登录' }, { status: 401 });
    }

    const token = authHeader.split(' ')[1];
    const decoded = jwt.verify(token, JWT_SECRET) as { userId: string };

    const { searchParams } = new URL(request.url);
    const learningId = searchParams.get('id');

    if (!learningId) {
      return NextResponse.json({ error: '缺少学习记录ID' }, { status: 400 });
    }

    const client = getSupabaseClient();

    // 获取学习记录
    const { data: learning } = await client
      .from('learning_library')
      .select('user_id, video_key')
      .eq('id', learningId)
      .single();

    if (!learning || (learning as any).user_id !== decoded.userId) {
      return NextResponse.json({ error: '记录不存在或无权删除' }, { status: 404 });
    }

    // 删除 TOS 文件
    const videoKey = (learning as any).video_key;
    if (videoKey) {
      try {
        await LearningLibraryStorage.deleteLearningVideo(videoKey as string);
      } catch {
        // 忽略删除错误
      }
    }

    // 删除数据库记录
    const { error } = await client
      .from('learning_library')
      .delete()
      .eq('id', learningId);

    if (error) {
      throw new Error(`删除失败: ${error.message}`);
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('删除学习记录错误:', error);

    if (error instanceof jwt.JsonWebTokenError) {
      return NextResponse.json({ error: '登录已过期' }, { status: 401 });
    }

    return NextResponse.json(
      { error: error instanceof Error ? error.message : '删除失败' },
      { status: 500 }
    );
  }
}

/**
 * 学习库上传确认 API
 * 
 * 前端上传完成后调用此 API，完成以下操作：
 * 1. 设置文件为永久公开读取
 * 2. 创建学习库记录
 * 3. 通知 Seed 2.0 有新数据（让它决定是否学习）
 * 
 * POST /api/learning-library/upload/confirm
 * 
 * 请求体：
 * {
 *   key: string;         // TOS key
 *   fileName: string;    // 文件名
 *   fileSize?: number;   // 文件大小
 *   publicUrl: string;   // 公开访问 URL
 * }
 * 
 * 返回：
 * {
 *   success: boolean;
 *   learning: { id, name, publicUrl, message };
 * }
 */

import { NextRequest, NextResponse } from 'next/server';
import { getSupabaseClient } from '@/storage/database/supabase-client';
import { VideoStorageService } from '@/lib/tos-storage';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

export async function POST(request: NextRequest) {
  try {
    // 验证用户身份
    const authHeader = request.headers.get('authorization');
    if (!authHeader?.startsWith('Bearer ')) {
      return NextResponse.json({ error: '未登录' }, { status: 401 });
    }

    const token = authHeader.split(' ')[1];
    const decoded = jwt.verify(token, JWT_SECRET) as { userId: string; username: string };

    const body = await request.json();
    const { key, fileName, fileSize, publicUrl } = body;

    if (!key || !fileName) {
      return NextResponse.json({ error: '缺少必要参数' }, { status: 400 });
    }

    // 验证文件归属（支持 videos 和 learning-videos 路径）
    const expectedPrefix = `users/${decoded.userId}/`;
    if (!key.startsWith(expectedPrefix)) {
      return NextResponse.json({ error: '无权访问此文件' }, { status: 403 });
    }

    // 设置为永久公开读取
    console.log(`[学习库确认] 设置永久公开读取: ${key}`);
    await VideoStorageService.setPublicRead(key);

    // 创建学习库记录
    const client = getSupabaseClient();
    const { data: learning, error: insertError } = await client
      .from('learning_library')
      .insert({
        user_id: decoded.userId,
        video_name: fileName,
        video_key: key,
        video_url: publicUrl,
        video_size: fileSize || 0,
        analysis_status: 'pending',
      })
      .select()
      .single();

    if (insertError) {
      console.error('[学习库确认] 创建记录失败:', insertError);
      return NextResponse.json({ error: '创建学习记录失败' }, { status: 500 });
    }

    if (!learning) {
      return NextResponse.json({ error: '创建学习记录失败' }, { status: 500 });
    }

    const learningAny = learning as any;

    console.log(`[学习库确认] 记录创建成功: ${learningAny.id}`);

    // 注意：这里不激活 Seed 2.0 进行分析
    // 只通知有新的偏好数据，由 Seed 2.0 决定是否学习
    // 通知方式：在创意小海的对话中可以看到学习库有更新

    return NextResponse.json({
      success: true,
      learning: {
        id: learningAny.id,
        name: fileName,
        publicUrl: publicUrl,
        message: '视频已保存到学习库，Seed 2.0 可以随时学习',
      },
    });

  } catch (error) {
    console.error('[学习库确认] 错误:', error);

    if (error instanceof jwt.JsonWebTokenError) {
      return NextResponse.json({ error: '登录已过期' }, { status: 401 });
    }

    return NextResponse.json(
      { error: error instanceof Error ? error.message : '确认上传失败' },
      { status: 500 }
    );
  }
}

/**
 * 学习库专用上传 API
 * 
 * 功能：为学习库提供文件上传能力
 * 
 * 特点：
 * 1. 后端代理上传（绕过 TOS CORS 限制）
 * 2. 上传后自动设置永久公开读取权限
 * 3. 存储到 learning_library 表
 * 
 * 流程：
 * 1. 前端将文件作为 FormData 发送到后端
 * 2. 后端接收文件并上传到 TOS
 * 3. 设置永久公开读取权限
 * 4. 返回永久公开 URL
 * 5. 存储到 learning_library 表
 * 
 * POST /api/learning-library/upload
 */

import { NextRequest, NextResponse } from 'next/server';
import { getSupabaseClient } from '@/storage/database/supabase-client';
import { getTosClient, BUCKET_NAME } from '@/lib/tos-storage';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';

// 文件大小限制：500MB
const MAX_FILE_SIZE = 500 * 1024 * 1024;

// 允许的文件类型
const ALLOWED_VIDEO_TYPES = ['video/mp4', 'video/quicktime', 'video/webm', 'video/x-msvideo'];

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

export async function POST(request: NextRequest) {
  try {
    // 验证用户身份
    const authHeader = request.headers.get('authorization');
    if (!authHeader?.startsWith('Bearer ')) {
      return NextResponse.json({ error: '未登录' }, { status: 401 });
    }

    const token = authHeader.split(' ')[1];
    const decoded = jwt.verify(token, JWT_SECRET) as { userId: string; username: string };

    const formData = await request.formData();
    const file = formData.get('file') as File | null;

    if (!file) {
      return NextResponse.json({ error: '请选择要上传的文件' }, { status: 400 });
    }

    // 验证文件类型
    if (!ALLOWED_VIDEO_TYPES.includes(file.type)) {
      return NextResponse.json({ error: '不支持的视频文件类型' }, { status: 400 });
    }

    // 验证文件大小
    if (file.size > MAX_FILE_SIZE) {
      return NextResponse.json({ error: '文件大小不能超过 500MB' }, { status: 400 });
    }

    // 生成唯一文件名
    const timestamp = Date.now();
    const extension = file.name.split('.').pop() || 'mp4';
    const key = `users/${decoded.userId}/learning-videos/video_${timestamp}.${extension}`;

    console.log(`[学习库上传] 开始上传: userId=${decoded.userId}, fileName=${file.name}, key=${key}, size=${file.size}`);

    // 读取文件内容
    const arrayBuffer = await file.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);

    // 上传到 TOS
    const client = getTosClient();
    await client.putObject({
      bucket: BUCKET_NAME,
      key,
      body: buffer,
      contentType: file.type,
    });

    // 设置永久公开读取权限
    try {
      await (client.putObjectAcl as any)({
        bucket: BUCKET_NAME,
        key,
        acl: 'public-read',
      });
      console.log(`[学习库上传] 设置永久公开读取成功: key=${key}`);
    } catch (aclError) {
      console.warn(`[学习库上传] 设置公开读取失败: ${aclError}`);
    }

    // 永久公开 URL（不包含签名）
    const publicUrl = `https://${BUCKET_NAME}.${process.env.TOS_ENDPOINT?.replace('https://', '') || 'tos-cn-beijing.volces.com'}/${key}`;

    console.log(`[学习库上传] 上传成功: key=${key}, publicUrl=${publicUrl}`);

    return NextResponse.json({
      success: true,
      key,
      publicUrl,
      contentType: file.type,
      size: file.size,
    });

  } catch (error) {
    console.error('[学习库上传] 错误:', error);
    return NextResponse.json(
      { error: error instanceof Error ? error.message : '上传失败' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getSupabaseClient } from '@/storage/database/supabase-client';
import { VideoStorageService } from '@/lib/tos-storage';
import { fail, normalizeText, requireAuth, toPositiveInt } from '@/lib/server/api-kit';

function isStablePublicUrl(url: unknown): url is string {
  if (typeof url !== 'string' || !url.startsWith('http')) return false;
  return !url.includes('X-Tos-Algorithm=') && !url.includes('X-Amz-Algorithm=');
}

/**
 * 素材历史 API
 * GET /api/material/history
 * 
 * 权限：
 * - material_member: 只能查看自己的素材
 * - material_leader: 可以查看团队成员的素材
 * - super_admin: 可以查看所有素材
 * 
 * 参数：
 * - type: 'personal' | 'team' (默认 personal)
 * - page: 页码
 * - limit: 每页数量
 * - status: 筛选状态
 * - userId: 指定用户ID（仅管理员可用）
 */
export async function GET(request: NextRequest) {
  try {
    const auth = requireAuth(request);
    if (auth.response || !auth.user) return auth.response;
    const decoded = auth.user;

    // 权限检查：财务角色无权访问
    if (decoded.role === 'finance') {
      return NextResponse.json({ error: '无权访问素材历史' }, { status: 403 });
    }

    const { searchParams } = new URL(request.url);
    const type = searchParams.get('type') === 'team' ? 'team' : 'personal';
    const page = toPositiveInt(searchParams.get('page'), 1);
    const limit = toPositiveInt(searchParams.get('limit'), 20, 1, 100);
    const status = normalizeText(searchParams.get('status'));
    const category = normalizeText(searchParams.get('category'));
    const keyword = normalizeText(searchParams.get('keyword'));
    const tag = normalizeText(searchParams.get('tag'));
    const version = searchParams.get('version') || 'all';
    const sourceVideoId = normalizeText(searchParams.get('sourceVideoId'));
    const targetVideoId = normalizeText(searchParams.get('id'));
    const targetUserId = normalizeText(searchParams.get('userId'));
    const sessionId = normalizeText(searchParams.get('sessionId'));

    const client = getSupabaseClient();
    const offset = (page - 1) * limit;

    // 根据角色和类型确定查询范围
    let queryUserIds: string[] = [];

    if (type === 'personal' || decoded.role === 'material_member') {
      // 个人视图 或 素材团队成员只能看自己的
      queryUserIds = [decoded.userId];
    } else if (type === 'team' && decoded.role === 'material_leader') {
      // 素材负责人查看团队成员（仅 material_member）
      const { data: teamMembers } = await client
        .from('users')
        .select('id')
        .eq('role', 'material_member');

      queryUserIds = (teamMembers as any[])?.map((m: any) => m.id as string) || [];
    } else if (decoded.role === 'super_admin') {
      // 超级管理员可以查看所有素材
      if (targetUserId) {
        // 指定了用户ID
        queryUserIds = [targetUserId];
      } else {
        // 不限制用户，查看所有素材
        queryUserIds = [];
      }
    }

    // ===== 同时查询 videos 表和 learning_library 表 =====

    const optionalColumns = [
      'task_id',
      'prompt',
      'session_id',
      'script',
      'copywriting',
      'tags',
      'tag_source',
      'auto_tag_status',
      'category',
      'reference_images',
      'generate_audio',
      'watermark',
      'web_search',
      'source_video_id',
      'source_task_id',
      'is_remix',
      'task_type',
      'tos_key',
      'public_video_url',
      'result_url',
      'ratio',
      'duration',
      'cost',
      'error_message',
      'model',
    ];
    const requiredColumns = ['id', 'user_id', 'status', 'created_at'];
    let availableOptional = new Set(optionalColumns);
    let videosData: any[] | null = null;
    let videosError: any = null;
    let attempts = 0;

    const buildVideoQuery = (availableColumns: Set<string>) => {
      const selectColumns = [...requiredColumns, ...optionalColumns.filter((col) => availableColumns.has(col))];
      let query = client
        .from('videos')
        .select(selectColumns.join(','))
        .order('created_at', { ascending: false });

      if (queryUserIds.length > 0) {
        query = query.in('user_id', queryUserIds);
      }
      if (status && ['pending', 'processing', 'completed', 'failed'].includes(status)) {
        query = query.eq('status', status);
      }
      if (category && availableColumns.has('category')) {
        query = query.eq('category', category);
      }
      if (keyword) {
        const keywordCols = ['prompt', 'script', 'copywriting'].filter((col) => col === 'prompt' || availableColumns.has(col));
        if (keywordCols.length > 0) {
          query = query.or(keywordCols.map((col) => `${col}.ilike.%${keyword}%`).join(','));
        }
      }
      if (tag && availableColumns.has('tags')) {
        query = query.contains('tags', [tag]);
      }
      if (version === 'remix' && availableColumns.has('is_remix')) {
        query = query.eq('is_remix', true);
      } else if (version === 'original' && availableColumns.has('is_remix')) {
        query = query.or('is_remix.is.null,is_remix.eq.false');
      }
      if (sourceVideoId && availableColumns.has('source_video_id')) {
        query = query.eq('source_video_id', sourceVideoId);
      }
      if (targetVideoId) {
        query = query.eq('id', targetVideoId);
      }
      if (sessionId && availableColumns.has('session_id')) {
        query = query.eq('session_id', sessionId);
      }
      return query;
    };

    while (attempts < 12) {
      attempts += 1;
      const result = await buildVideoQuery(availableOptional);
      videosData = result.data;
      videosError = result.error;
      if (!videosError) break;

      const message = String(videosError.message || '');
      const missingColumnMatch = message.match(/column\s+"?([a-zA-Z0-9_]+)"?\s+does not exist/i);
      const missingColumn = missingColumnMatch?.[1];
      if (!missingColumn || !availableOptional.has(missingColumn)) {
        break;
      }
      console.warn(`videos.${missingColumn} 不存在，自动降级并重试`);
      availableOptional.delete(missingColumn);
    }

    if (videosError) {
      throw new Error(`查询 videos 表失败: ${videosError.message}`);
    }

    // 2. 查询 learning_library 表（仅查询已完成的视频）
    let learningQuery = client
      .from('learning_library')
      .select(`
        id,
        user_id,
        video_name,
        video_url,
        video_size,
        video_duration,
        video_style,
        summary,
        analysis_status,
        created_at
      `)
      .eq('analysis_status', 'completed')  // 仅查询已分析完成的视频
      .order('created_at', { ascending: false });

    // 应用用户筛选
    if (queryUserIds.length > 0) {
      learningQuery = learningQuery.in('user_id', queryUserIds);
    }

    const { data: learningData, error: learningError } = await learningQuery;

    if (learningError) {
      throw new Error(`查询 learning_library 表失败: ${learningError.message}`);
    }

    // 3. 合并两个表的结果
    let mergedVideos: Array<{
      id: string;
      user_id: string;
      session_id?: string | null;
      task_id?: string | null;
      prompt: string;
      script?: string | null;
      copywriting?: string | null;
      tags?: string[] | null;
      tag_source?: string | null;
      auto_tag_status?: string | null;
      category?: string | null;
      reference_images?: string[] | null;
      generate_audio?: boolean | null;
      watermark?: boolean | null;
      web_search?: boolean | null;
      source_video_id?: string | null;
      source_task_id?: string | null;
      is_remix?: boolean | null;
      task_type: string;
      status: string;
      tos_key: string | null;
      public_video_url?: string | null;
      result_url: string | null;
      ratio: string;
      duration: number;
      cost: number | null;
      error_message?: string | null;
      created_at: string;
      model?: string;
      video_url?: string;  // 用于前端显示
      video_name?: string;  // 学习库视频名称
      error_reason?: string | null;  // 错误原因
      source: 'videos' | 'learning_library';  // 标识数据来源
    }> = [];

    // 添加 videos 表的数据
    const videoUrls = new Set<string>();  // 用于去重
    if (videosData) {
      for (const video of videosData) {
        const v = video as any;
        const urlKey = v.public_video_url || v.result_url || v.tos_key || v.id;
        if (!videoUrls.has(urlKey as string)) {
          videoUrls.add(urlKey as string);
          mergedVideos.push({
            id: v.id,
            user_id: v.user_id,
            session_id: (v.session_id as string) || null,
            task_id: v.task_id as string,
            prompt: (v.prompt as string) || '视频生成任务',
            script: (v.script as string) || null,
            copywriting: (v.copywriting as string) || null,
            tags: (v.tags as string[]) || [],
            tag_source: (v.tag_source as string) || null,
            auto_tag_status: (v.auto_tag_status as string) || null,
            category: (v.category as string) || null,
            reference_images: (v.reference_images as string[]) || [],
            generate_audio: v.generate_audio ?? true,
            watermark: v.watermark ?? false,
            web_search: v.web_search ?? false,
            source_video_id: (v.source_video_id as string) || null,
            source_task_id: (v.source_task_id as string) || null,
            is_remix: Boolean(v.is_remix),
            task_type: v.task_type || 'text_to_video',
            status: v.status || 'completed',
            tos_key: v.tos_key,
            public_video_url: (v.public_video_url as string) || null,
            result_url: v.result_url,
            ratio: v.ratio || '16:9',
            duration: v.duration || 0,
            cost: v.cost,
            error_reason: v.error_reason,
            error_message: v.error_message,
            created_at: v.created_at,
            model: v.model || 'doubao-seedance-2-0',
            video_url: (v.public_video_url as string) || v.result_url,
            source: 'videos',
          });
        }
      }
    }

    // 添加 learning_library 表的数据
    if (learningData) {
      for (const learning of learningData) {
        const l = learning as any;
        const urlKey = l.video_url || l.id;
        // 仅当 videos 表中没有相同 URL 时才添加
        if (!videoUrls.has(urlKey as string)) {
          videoUrls.add(urlKey as string);
          mergedVideos.push({
            id: l.id,
            user_id: l.user_id,
            video_name: l.video_name,
            prompt: (l.video_name as string) || (l.summary as string) || '学习库视频',
            task_type: 'learning_library',
            status: 'completed',  // 学习库中的视频都是已完成的
            tos_key: null,
            result_url: l.video_url,
            ratio: '9:16',  // 默认值
            duration: (l.video_duration as number) || 0,
            cost: null,
            error_reason: null,
            error_message: null,
            created_at: l.created_at,
            model: 'doubao-seedance-2-0',  // 默认值
            video_url: l.video_url,
            source: 'learning_library',
          });
        }
      }
    }

    // 4. 二次筛选（兼容 learning_library 数据）
    if (tag) {
      mergedVideos = mergedVideos.filter((video) => Array.isArray(video.tags) && video.tags.includes(tag));
    }

    // 5. 按创建时间排序
    mergedVideos.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());

    // 6. 分页
    const total = mergedVideos.length;
    const paginatedVideos = mergedVideos.slice(offset, offset + limit);
    const count = total;  // 用于计算总页数

    // 获取所有相关的用户 ID
    const userIds = [...new Set(paginatedVideos.map(v => v.user_id))];

    // 批量查询用户信息
    const { data: usersData } = await client
      .from('users')
      .select('id, username, email, role')
      .in('id', userIds);

    // 创建用户 ID 到用户信息的映射
    const userMap = new Map((usersData || []).map(u => [u.id, u]));

    // 为完成的视频生成 URL
    const videosWithUrl = await Promise.all(
      paginatedVideos.map(async (video) => {
        let videoUrl = (video as any).public_video_url || video.result_url || video.video_url;

        // 如果没有 result_url，但有 TOS key 且状态为完成，生成签名 URL
        if (!videoUrl && video.tos_key && video.status === 'completed') {
          try {
            videoUrl = VideoStorageService.getVideoPublicUrl(video.tos_key);
            await client
              .from('videos')
              .update({
                public_video_url: videoUrl,
                result_url: isStablePublicUrl(video.result_url) ? video.result_url : videoUrl,
                updated_at: new Date().toISOString(),
              })
              .eq('id', video.id);
          } catch (e) {
            console.error(`生成签名 URL 失败: ${video.id}`, e);
          }
        }

        // 从映射中获取用户信息
        const userInfo = userMap.get(video.user_id);

        return {
          ...video,
          video_url: videoUrl,
          users: userInfo || null,
        };
      })
    );

    return NextResponse.json({
      success: true,
      videos: videosWithUrl,
      pagination: {
        page,
        limit,
        total: count || 0,
        totalPages: Math.ceil((count || 0) / limit),
      },
      filter: {
        type,
        status,
        version,
        userIds: queryUserIds,
      },
    });
  } catch (error) {
    console.error('查询素材历史失败:', error);

    return fail(error instanceof Error ? error.message : '查询失败', 500);
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getSupabaseClient } from '@/storage/database/supabase-client';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';

/**
 * 每日消费统计 API
 * GET /api/stats/daily?startDate=2024-01-01&endDate=2024-01-31
 */
export async function GET(request: NextRequest) {
  // 辅助函数：格式化金额（处理 BigNumber 等特殊格式）
  const formatAmount = (val: unknown): number => {
    if (typeof val === 'number') return val;
    if (typeof val === 'string') {
      const num = parseFloat(val);
      return isNaN(num) ? 0 : num;
    }
    if (val && typeof val === 'object' && typeof (val as { toString?: () => string }).toString === 'function') {
      const str = (val as { toString: () => string }).toString();
      const num = parseFloat(str);
      return isNaN(num) ? 0 : num;
    }
    return 0;
  };

  try {
    const authHeader = request.headers.get('authorization');
    if (!authHeader?.startsWith('Bearer ')) {
      return NextResponse.json({ error: '未登录' }, { status: 401 });
    }

    const token = authHeader.split(' ')[1];
    const decoded = jwt.verify(token, JWT_SECRET) as { role: string };

    // 仅管理员和财务可访问
    if (!['super_admin', 'finance'].includes(decoded.role)) {
      return NextResponse.json({ error: '无权限' }, { status: 403 });
    }

    const { searchParams } = new URL(request.url);
    const startDate = searchParams.get('startDate') || new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
    const endDate = searchParams.get('endDate') || new Date().toISOString().split('T')[0];

    const client = getSupabaseClient();

    // 查询账单数据并按日期分组
    const { data, error } = await client
      .from('billing')
      .select('created_at, amount, task_type')
      .gte('created_at', startDate)
      .lte('created_at', `${endDate}T23:59:59`)
      .order('created_at', { ascending: true });

    if (error) {
      throw new Error(`查询失败: ${error.message}`);
    }

    // 按日期和类型统计
    const statsMap = new Map<string, { date: string; category: string; amount: number; tasks: number }>();

    (data || []).forEach((item: any) => {
      const date = (item.created_at as string)?.split('T')[0] || '';
      const category = (item.task_type as string) || 'other';
      const key = `${date}_${category}`;

      if (!statsMap.has(key)) {
        statsMap.set(key, {
          date,
          category,
          amount: 0,
          tasks: 0,
        });
      }

      const stat = statsMap.get(key)!;
      stat.amount += formatAmount(item.amount);
      stat.tasks += 1;
    });

    const stats = Array.from(statsMap.values()).map(stat => ({
      stat_date: stat.date,
      category: stat.category,
      total_amount: stat.amount,
      total_tasks: stat.tasks,
    }));

    // 计算总计
    const totalAmount = stats.reduce((sum, s) => sum + s.total_amount, 0);
    const totalTasks = stats.reduce((sum, s) => sum + s.total_tasks, 0);

    return NextResponse.json({
      stats,
      summary: {
        total_amount: totalAmount,
        total_tasks: totalTasks,
        date_range: { start: startDate, end: endDate },
      },
    });
  } catch (error) {
    console.error('查询统计错误:', error);
    return NextResponse.json(
      { error: error instanceof Error ? error.message : '查询失败' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getSupabaseClient } from '@/storage/database/supabase-client';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';

/**
 * 仪表盘统计概览 API
 * GET /api/stats/overview
 */
export async function GET(request: NextRequest) {
  // 辅助函数：格式化金额（处理 BigNumber 等特殊格式）
  const formatAmount = (val: unknown): number => {
    if (typeof val === 'number') return val;
    if (typeof val === 'string') {
      const num = parseFloat(val);
      return isNaN(num) ? 0 : num;
    }
    if (val && typeof val === 'object' && typeof (val as { toString?: () => string }).toString === 'function') {
      const str = (val as { toString: () => string }).toString();
      const num = parseFloat(str);
      return isNaN(num) ? 0 : num;
    }
    return 0;
  };

  try {
    const authHeader = request.headers.get('authorization');
    if (!authHeader?.startsWith('Bearer ')) {
      return NextResponse.json({ error: '未登录' }, { status: 401 });
    }

    const token = authHeader.split(' ')[1];
    const decoded = jwt.verify(token, JWT_SECRET) as {
      userId: string;
      role: string;
    };

    const client = getSupabaseClient();
    const isAdmin = ['super_admin', 'admin'].includes(decoded.role);

    // 用户视频统计
    const { data: videoStats, error: videoError } = await client
      .from('videos')
      .select('status', { count: 'exact', head: false })
      .eq('user_id', decoded.userId);

    if (videoError) {
      throw new Error(`查询视频统计失败: ${videoError.message}`);
    }

    const totalVideos = (videoStats as any[])?.length || 0;
    const pendingVideos = (videoStats as any[])?.filter((v: any) => v.status === 'processing').length || 0;

    // 用户消费统计
    const { data: billingStats, error: billingError } = await client
      .from('billing')
      .select('amount')
      .eq('user_id', decoded.userId);

    if (billingError) {
      throw new Error(`查询账单统计失败: ${billingError.message}`);
    }

    const totalAmount = billingStats?.reduce((sum: number, b) => sum + formatAmount(b.amount), 0) || 0;

    const response: Record<string, unknown> = {
      total_videos: totalVideos,
      pending_videos: pendingVideos,
      total_amount: totalAmount.toFixed(2),
    };

    // 管理员额外统计
    if (isAdmin) {
      // 用户总数
      const { count: totalUsers, error: userError } = await client
        .from('users')
        .select('*', { count: 'exact', head: true });

      if (!userError) {
        response.total_users = totalUsers || 0;
      }

      // 本月消费
      const now = new Date();
      const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();

      const { data: monthlyBilling, error: monthlyError } = await client
        .from('billing')
        .select('amount')
        .gte('created_at', monthStart);

      if (!monthlyError) {
        const monthlyAmount = monthlyBilling?.reduce((sum: number, b) => sum + formatAmount(b.amount), 0) || 0;
        response.monthly_amount = monthlyAmount.toFixed(2);
      }
    }

    return NextResponse.json(response);
  } catch (error) {
    console.error('查询统计概览错误:', error);
    return NextResponse.json(
      { error: error instanceof Error ? error.message : '查询失败' },
      { status: 500 }
    );
  }
}

/**
 * 批量视频生成 API
 * 
 * POST /api/template/batch-generate
 * 使用模板批量生成视频
 */

import { NextRequest, NextResponse } from 'next/server';
import { ScriptTemplateService } from '@/lib/script-template-service';
import { SeedanceClient } from '@/lib/seedance-client';
import { getSupabaseClient } from '@/storage/database/supabase-client';
import { TaskStateService } from '@/lib/server/task-state-service';
import { requireAuth } from '@/lib/server/api-kit';
import { v4 as uuidv4 } from 'uuid';

const templateService = new ScriptTemplateService();
const seedanceClient = new SeedanceClient();
const taskStateService = new TaskStateService();

// 最大批量数量限制
const MAX_BATCH_SIZE = 20;

interface TaskResult {
  rowIndex: number;
  success: boolean;
  taskId?: string;
  prompt?: string;
  error?: string;
}

/**
 * POST /api/template/batch-generate
 */
export async function POST(request: NextRequest) {
  try {
    const auth = requireAuth(request);
    if (auth.response || !auth.user) return auth.response;
    const userId = auth.user.userId;
    const supabase = getSupabaseClient();

    const body = await request.json();
    const { template_id, data_rows, first_frame_url, session_id } = body;

    if (!template_id || !data_rows || !Array.isArray(data_rows)) {
      return NextResponse.json({ error: '参数错误' }, { status: 400 });
    }

    // 检查批量数量限制
    if (data_rows.length > MAX_BATCH_SIZE) {
      return NextResponse.json({ 
        error: `单次批量数量不能超过 ${MAX_BATCH_SIZE} 个` 
      }, { status: 400 });
    }

    // 获取模板
    const templateResult = await templateService.getTemplate(template_id);
    if (!templateResult.success || !templateResult.data) {
      return NextResponse.json({ error: '模板不存在' }, { status: 404 });
    }

    const template = templateResult.data;
    const activeSessionId = typeof session_id === 'string' && session_id ? session_id : null;
    if (!activeSessionId) {
      return NextResponse.json({ error: '缺少 session_id' }, { status: 400 });
    }

    const parentTask = await taskStateService.ensureTask({
      userId,
      sessionId: activeSessionId,
      taskType: 'batch_generate',
      clientRequestId: typeof body?.client_request_id === 'string' ? body.client_request_id : `batch_${Date.now()}`,
      inputData: {
        template_id,
        total_rows: data_rows.length,
        first_frame_url: first_frame_url || null,
      },
    });

    // 解析模板并批量生成
    const parseResult = templateService.parseTemplateBatch(template, data_rows);

    // 构造批量任务
    const tasks: Array<{ prompt: string; variables: Record<string, string> }> = [];

    parseResult.results.forEach((result, index) => {
      if (result.success) {
        tasks.push({
          prompt: result.prompt,
          variables: data_rows[index]
        });
      }
    });

    // 提交批量任务
    const taskResults: TaskResult[] = [];
    let submittedCount = 0;

    for (let i = 0; i < parseResult.results.length; i++) {
      const result = parseResult.results[i];
      const rowIndex = i;

      if (!result.success) {
        taskResults.push({
          rowIndex,
          success: false,
          error: result.errors?.join(', ') || '变量解析失败'
        });
        continue;
      }

      try {
        const videoId = uuidv4();
        // 调用 Seedance 生成视频
        let videoResult;
        if (first_frame_url) {
          // 有首帧图：使用图生视频
          videoResult = await seedanceClient.imageToVideo(first_frame_url, result.prompt, {
            model: 'doubao-seedance-2-0-260128',
            duration: template.duration,
            ratio: template.aspect_ratio as any,
          });
        } else {
          // 无首帧图：使用文生视频
          videoResult = await seedanceClient.textToVideo(result.prompt, {
            model: 'doubao-seedance-2-0-260128',
            duration: template.duration,
            ratio: template.aspect_ratio as any,
          });
        }

        // videoResult 是 GetTaskResponse
        if (videoResult.id) {
          await supabase.from('videos').insert({
            id: videoId,
            task_id: videoResult.id,
            user_id: userId,
            session_id: activeSessionId,
            prompt: result.prompt,
            task_type: first_frame_url ? 'image_to_video' : 'text_to_video',
            status: 'processing',
            ratio: template.aspect_ratio,
            duration: template.duration,
            model: 'doubao-seedance-2-0-260128',
            tags: ['batch_generate', `template:${template_id}`],
            video_name: `批量视频 ${rowIndex + 1}`,
          });
          await taskStateService.appendTaskItem({
            taskId: parentTask.id,
            userId,
            sessionId: activeSessionId,
            status: 'succeeded',
            inputData: {
              rowIndex,
              prompt: result.prompt,
              variables: data_rows[rowIndex] || {},
            },
            outputData: {
              seedance_task_id: videoResult.id,
              video_id: videoId,
            },
          });
          taskResults.push({
            rowIndex,
            success: true,
            taskId: videoResult.id,
            prompt: result.prompt
          });
          submittedCount++;
        } else {
          await taskStateService.appendTaskItem({
            taskId: parentTask.id,
            userId,
            sessionId: activeSessionId,
            status: 'failed',
            inputData: {
              rowIndex,
              prompt: result.prompt,
              variables: data_rows[rowIndex] || {},
            },
            errorMessage: '提交失败',
          });
          taskResults.push({
            rowIndex,
            success: false,
            error: '提交失败'
          });
        }
      } catch (error) {
        await taskStateService.appendTaskItem({
          taskId: parentTask.id,
          userId,
          sessionId: activeSessionId,
          status: 'failed',
          inputData: {
            rowIndex,
            prompt: result.prompt,
            variables: data_rows[rowIndex] || {},
          },
          errorMessage: error instanceof Error ? error.message : '提交失败',
        });
        taskResults.push({
          rowIndex,
          success: false,
          error: error instanceof Error ? error.message : '提交失败'
        });
      }
    }

    // 更新模板使用次数
    await templateService.incrementUsage(template_id);
    await taskStateService.aggregateTaskFromItems(parentTask.id);
    await taskStateService.appendEvent(parentTask.id, userId, activeSessionId, 'batch_generate_submitted', {
      total: data_rows.length,
      submitted: submittedCount,
    });

    // 返回结果
    return NextResponse.json({
      success: true,
      batch_summary: {
        total: data_rows.length,
        valid: tasks.length,
        submitted: submittedCount,
        failed: parseResult.errorCount + (taskResults.filter(r => !r.success).length - parseResult.errorCount)
      },
      worker_task_id: parentTask.id,
      results: taskResults
    });

  } catch (error) {
    console.error('批量生成失败:', error);
    return NextResponse.json({ error: '批量生成失败' }, { status: 500 });
  }
}

/**
 * TOS CORS 配置 API
 * 
 * 功能：配置 TOS 存储桶的跨域规则，允许浏览器直接上传
 * 
 * 方式：直接调用 TOS API，使用正确的 XML 格式
 * 
 * POST /api/tos/cors
 */

import { NextResponse } from 'next/server';
import { getTosClient, BUCKET_NAME, ENDPOINT } from '@/lib/tos-storage';

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

// 支持的域名列表
const ALLOWED_ORIGINS = [
  'https://*.dev.coze.site',
  'https://*.coze.site',
  'https://*.coze.cn',
];

export async function POST() {
  try {
    console.log('[TOS CORS] 开始配置跨域规则...');

    // 使用 SDK 的底层方法
    const client = getTosClient();

    // 构建 CORS XML 配置
    const corsRules = ALLOWED_ORIGINS.map(origin => `
    <CORSRule>
      <AllowedOrigin>${origin}</AllowedOrigin>
      <AllowedMethod>GET</AllowedMethod>
      <AllowedMethod>PUT</AllowedMethod>
      <AllowedMethod>POST</AllowedMethod>
      <AllowedMethod>DELETE</AllowedMethod>
      <AllowedMethod>HEAD</AllowedMethod>
      <AllowedHeader>*</AllowedHeader>
      <MaxAgeSeconds>3600</MaxAgeSeconds>
    </CORSRule>`).join('');

    const corsXml = `<?xml version="1.0" encoding="UTF-8"?>
<CORSConfiguration>
${corsRules}
</CORSConfiguration>`;

    console.log('[TOS CORS] 发送 CORS 配置...');

    // 直接使用 SDK 的请求方法
    const result = await (client as any).fetchBucket(BUCKET_NAME, 'PUT', { cors: '' }, {}, { data: corsXml });

    console.log('[TOS CORS] 跨域规则配置成功:', result);

    return NextResponse.json({
      success: true,
      message: 'CORS 配置成功',
      allowedOrigins: ALLOWED_ORIGINS,
    });

  } catch (error: any) {
    console.error('[TOS CORS] 配置失败:', error);
    return NextResponse.json(
      { error: error?.message || 'CORS 配置失败' },
      { status: 500 }
    );
  }
}

// 获取当前 CORS 配置
export async function GET() {
  try {
    const client = getTosClient();

    const result = await client.getBucketCORS({
      bucket: BUCKET_NAME,
    }) as any;

    return NextResponse.json({
      success: true,
      corsRules: result.CORSRules || [],
    });

  } catch (error: any) {
    // 如果不存在，返回空配置
    if (error?.code === 'NoSuchCORSConfiguration') {
      return NextResponse.json({
        success: true,
        corsRules: [],
        message: 'CORS 配置不存在',
      });
    }
    console.error('[TOS CORS] 获取配置失败:', error);
    return NextResponse.json(
      { error: error?.message || '获取 CORS 配置失败' },
      { status: 500 }
    );
  }
}

/**
 * 通用文件上传 - 确认上传完成
 * 
 * 功能：前端上传完成后调用，设置文件为公开读取
 * 
 * POST /api/upload/confirm
 * Body: { key: string }
 * Response: { success: boolean, publicUrl: string }
 */

import { NextRequest, NextResponse } from 'next/server';
import { getTosClient, BUCKET_NAME } from '@/lib/tos-storage';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

export async function POST(request: NextRequest) {
  try {
    // 验证用户身份
    const authHeader = request.headers.get('authorization');
    if (!authHeader?.startsWith('Bearer ')) {
      return NextResponse.json({ error: '未登录' }, { status: 401 });
    }

    const token = authHeader.split(' ')[1];
    const decoded = jwt.verify(token, JWT_SECRET) as { userId: string; username: string };

    const body = await request.json();
    const { key } = body;

    if (!key) {
      return NextResponse.json({ error: '缺少 key' }, { status: 400 });
    }

    // 验证文件路径属于当前用户（安全检查）
    const expectedPrefix = `users/${decoded.userId}/`;
    if (!key.startsWith(expectedPrefix)) {
      return NextResponse.json({ error: '非法文件路径' }, { status: 403 });
    }

    // 设置文件为公开读取
    const client = getTosClient();
    try {
      await (client.putObjectAcl as any)({
        bucket: BUCKET_NAME,
        key: key,
        acl: 'public-read',
      });
    } catch (aclError) {
      console.warn('[上传确认] 设置公开权限失败，继续使用原 URL:', aclError);
    }

    // 生成公开 URL
    const publicUrl = `https://${BUCKET_NAME}.tos-cn-beijing.volces.com/${key}`;

    console.log(`[上传确认] 设置公开: userId=${decoded.userId}, key=${key}`);

    return NextResponse.json({
      success: true,
      publicUrl,
    });

  } catch (error) {
    console.error('[上传确认] 失败:', error);

    if (error instanceof jwt.JsonWebTokenError) {
      return NextResponse.json({ error: '登录已过期' }, { status: 401 });
    }

    return NextResponse.json(
      { error: error instanceof Error ? error.message : '确认上传失败' },
      { status: 500 }
    );
  }
}

