import { NextRequest, NextResponse } from 'next/server';
import { getSupabaseClient } from '@/storage/database/supabase-client';
import { SeedanceClient, Content, VideoRatio, SeedanceModel } from '@/lib/seedance-client';
import { VideoStorageService } from '@/lib/tos-storage';
import { fail, normalizeText, requireAuth } from '@/lib/server/api-kit';
import { TaskStateService } from '@/lib/server/task-state-service';

// 初始化 Seedance 客户端
const seedanceClient = new SeedanceClient();
const taskStateService = new TaskStateService();

async function findVideoWorkerTaskId(userId: string, videoId: string): Promise<string | null> {
  const supabase = getSupabaseClient();
  const { data } = await supabase
    .from('worker_tasks')
    .select('id')
    .eq('user_id', userId)
    .eq('task_type', 'video_generate')
    .contains('input_data', { video_id: videoId })
    .order('created_at', { ascending: false })
    .limit(1);
  const first = Array.isArray(data) ? data[0] : null;
  return first?.id ? String(first.id) : null;
}

function deriveAutoTags(input: {
  prompt?: string | null;
  script?: string | null;
  copywriting?: string | null;
  category?: string | null;
  isRemix?: boolean;
}, candidatePool: string[]): string[] {
  const merged = `${input.prompt || ''}\n${input.script || ''}\n${input.copywriting || ''}\n${input.category || ''}`.toLowerCase();
  const picked: string[] = [];

  for (const tag of candidatePool) {
    if (picked.length >= 5) break;
    if (merged.includes(tag.toLowerCase())) picked.push(tag);
  }

  if (input.category && !picked.includes(input.category)) picked.push(input.category);
  if (input.isRemix && !picked.includes('REMIX')) picked.push('REMIX');

  if (picked.length === 0) {
    if (merged.includes('测评')) picked.push('测评');
    if (merged.includes('开箱')) picked.push('开箱');
    if (merged.includes('教程')) picked.push('教程');
    if (picked.length === 0) picked.push('种草');
  }

  return Array.from(new Set(picked)).slice(0, 5);
}

/**
 * 视频生成 API (Seedance 2.0)
 * POST /api/video/generate
 * 
 * 请求体：
 * {
 *   prompt: string;              // 视频提示词
 *   taskType?: 'generate' | 'edit' | 'extend';  // 任务类型
 *   model?: SeedanceModel;       // 模型选择
 *   
 *   // 首尾帧
 *   firstFrame?: string;         // 首帧图片 URL
 *   lastFrame?: string;          // 尾帧图片 URL
 *   
 *   // 多模态参考
 *   referenceImages?: string[];  // 参考图片 URL 列表 (最多9张)
 *   realAssetId?: string;         // 真人演员素材 ID（将转为 asset:// 引用）
 *   referenceVideos?: string[];  // 参考视频 URL 列表 (最多3个)
 *   referenceAudios?: string[];  // 参考音频 URL 列表 (最多3个)
 *   
 *   // 视频参数
 *   ratio?: VideoRatio;          // 比例
 *   duration?: number;           // 时长（4-15秒）
 *   generateAudio?: boolean;     // 是否生成音频
 *   watermark?: boolean;         // 是否添加水印
 *   webSearch?: boolean;         // 是否启用联网搜索
 * }
 */
export async function POST(request: NextRequest) {
  try {
    const auth = requireAuth(request);
    if (auth.response || !auth.user) return auth.response;
    const decoded = auth.user;

    const body = await request.json();
    const {
      prompt,
      taskType = 'generate',
      model = 'doubao-seedance-2-0-260128',
      firstFrame,
      lastFrame,
      referenceImages = [],
      realAssetId,
      referenceVideos = [],
      referenceAudios = [],
      sourceVideoId,
      sourceTaskId,
      sessionId,
      isRemix = false,
      ratio = '16:9',
      duration = 5,
      generateAudio = true,
      watermark = false,
      webSearch = false,
    } = body;

    if (!prompt) {
      return fail('提示词不能为空', 400);
    }

    // 验证参数
    if (duration < 4 || duration > 15) {
      return fail('视频时长必须在4-15秒之间', 400);
    }

    if (referenceImages.length > 9) {
      return fail('参考图片最多9张', 400);
    }

    const normalizedReferenceImages = [...referenceImages];
    if (realAssetId) {
      normalizedReferenceImages.push(`asset://${realAssetId}`);
    }

    if (referenceVideos.length > 3) {
      return fail('参考视频最多3个', 400);
    }

    if (referenceAudios.length > 3) {
      return fail('参考音频最多3个', 400);
    }

    // 创建视频任务记录
    const supabase = getSupabaseClient();
    const { data: videoTask, error: insertError } = await supabase
      .from('videos')
      .insert({
        user_id: decoded.userId,
        prompt,
        task_type: taskType,
        model,
        reference_images: normalizedReferenceImages.length > 0 ? normalizedReferenceImages : null,
        reference_videos: referenceVideos.length > 0 ? referenceVideos : null,
        reference_audios: referenceAudios.length > 0 ? referenceAudios : null,
        first_frame: firstFrame || null,
        last_frame: lastFrame || null,
        ratio,
        duration,
        generate_audio: generateAudio,
        watermark,
        web_search: webSearch,
        source_video_id: normalizeText(sourceVideoId) || null,
        source_task_id: normalizeText(sourceTaskId) || null,
        session_id: normalizeText(sessionId) || null,
        is_remix: Boolean(isRemix),
        status: 'processing',
      })
      .select()
      .single();

    if (insertError) {
      throw new Error(`创建任务失败: ${insertError.message}`);
    }
    const videoId = String((videoTask as any).id);

    let workerTaskId: string | null = null;
    if (sessionId) {
      const ensured = await taskStateService.ensureTask({
        userId: decoded.userId,
        sessionId: String(sessionId),
        taskType: 'video_generate',
        clientRequestId: `video_generate_${videoId}`,
        inputData: {
          video_id: videoId,
          prompt,
          ratio,
          duration,
          task_type: taskType,
        },
      });
      workerTaskId = ensured.id;
      await taskStateService.appendEvent(ensured.id, decoded.userId, String(sessionId), 'video_generate_submitted', {
        video_id: videoId,
      });
    }

    // 构建 Seedance 2.0 内容数组
    const content: Content[] = [];

    // 1. 首帧图片
    if (firstFrame) {
      content.push({
        type: 'image_url',
        image_url: { url: firstFrame },
        role: 'first_frame',
      });
    }

    // 2. 尾帧图片
    if (lastFrame) {
      content.push({
        type: 'image_url',
        image_url: { url: lastFrame },
        role: 'last_frame',
      });
    }

    // 3. 参考图片
    for (const url of normalizedReferenceImages) {
      if (url) {
        content.push({
          type: 'image_url',
          image_url: { url },
          role: 'reference_image',
        });
      }
    }

    // 4. 参考视频
    for (const url of referenceVideos) {
      if (url) {
        content.push({
          type: 'video_url',
          video_url: { url },
          role: 'reference_video',
        });
      }
    }

    // 5. 参考音频
    for (const url of referenceAudios) {
      if (url) {
        content.push({
          type: 'audio_url',
          audio_url: { url },
          role: 'reference_audio',
        });
      }
    }

    // 6. 文本提示词（放在最后）
    content.push({
      type: 'text',
      text: prompt,
    });

    // 调用 Seedance 2.0 API
    try {
      const taskResponse = await seedanceClient.createTask({
        model: model as SeedanceModel,
        content,
        generate_audio: generateAudio,
        ratio: ratio as VideoRatio,
        duration,
        watermark,
        tools: webSearch ? [{ type: 'web_search' }] : undefined,
      });

      // 更新任务ID
      await supabase
        .from('videos')
        .update({ task_id: taskResponse.id })
        .eq('id', videoId);

      if (workerTaskId && sessionId) {
        await taskStateService.transitionTask(workerTaskId, 'running', {
          progress: 25,
          output_data: { video_id: videoId, seedance_task_id: taskResponse.id },
        });
        await taskStateService.appendEvent(workerTaskId, decoded.userId, String(sessionId), 'video_generate_processing', {
          video_id: videoId,
          seedance_task_id: taskResponse.id,
        });
      }

      // 返回任务信息，让前端轮询
      return NextResponse.json({
        success: true,
        taskId: videoId,
        workerTaskId,
        seedanceTaskId: taskResponse.id,
        status: 'processing',
        message: '任务已提交，请轮询查询状态',
      });

    } catch (apiError) {
      // 更新任务状态为失败
      await supabase
        .from('videos')
        .update({
          status: 'failed',
          error_message: apiError instanceof Error ? apiError.message : 'API调用失败',
        })
        .eq('id', videoId);

      const linkedWorkerTaskId = workerTaskId || await findVideoWorkerTaskId(decoded.userId, videoId);
      if (linkedWorkerTaskId && sessionId) {
        await taskStateService.transitionTask(linkedWorkerTaskId, 'failed', {
          progress: 100,
          completed_at: new Date().toISOString(),
          error_message: apiError instanceof Error ? apiError.message : 'API调用失败',
          output_data: { video_id: videoId },
        });
        await taskStateService.appendEvent(linkedWorkerTaskId, decoded.userId, String(sessionId), 'video_generate_failed', {
          video_id: videoId,
          error: apiError instanceof Error ? apiError.message : 'API调用失败',
        });
      }

      throw apiError;
    }

  } catch (error) {
    console.error('视频生成错误:', error);

    return fail(error instanceof Error ? error.message : '视频生成失败', 500);
  }
}

/**
 * 查询视频任务
 * GET /api/video/generate?taskId=xxx
 */
export async function GET(request: NextRequest) {
  try {
    const auth = requireAuth(request);
    if (auth.response || !auth.user) return auth.response;
    const decoded = auth.user;

    const { searchParams } = new URL(request.url);
    const taskId = searchParams.get('taskId');

    const supabase = getSupabaseClient();

    if (taskId) {
      // 查询单个任务
      const { data, error } = await supabase
        .from('videos')
        .select('*')
        .eq('id', taskId)
        .eq('user_id', decoded.userId)
        .single();

      if (error) {
      return fail('任务不存在', 404);
      }

      const video = data as any;

      // 如果任务还在处理中，尝试从 Seedance 获取最新状态
      if (video.status === 'processing' && video.task_id) {
        try {
          const seedanceTask = await seedanceClient.getTask(video.task_id);

          if (seedanceTask.status === 'succeeded' && seedanceTask.content?.video_url) {
            console.log(`[Video] 任务 ${video.id} 完成，开始存储到 TOS...`);

            // 获取 Token 用量（注意：API 可能只返回 total_tokens）
            const totalTokens = seedanceTask.usage?.total_tokens || 0;

            // 根据是否有视频输入决定价格
            // task_type 为 edit/extend 时有视频输入（28元/百万tokens），否则为纯生成（46元/百万tokens）
            const hasVideoInput = video.task_type === 'edit' || video.task_type === 'extend';
            const unitPrice = hasVideoInput ? 28 : 46; // 元/百万tokens

            // 计算真实成本
            const cost = totalTokens > 0 
              ? Math.round((totalTokens / 1_000_000) * unitPrice * 100) / 100
              : (video.duration || 5) * 0.1; // 如果没有 token 数据，使用估算

            console.log(`[Video] Token 用量: ${totalTokens}, 单价: ${unitPrice}元/百万tokens, 成本: ${cost}元`);

            // 存储视频到 TOS
            let tosKey: string | null = null;
            let lastFrameTosKey: string | null = null;

            try {
              // 上传视频到 TOS
              tosKey = await VideoStorageService.storeVideoFromUrl(
                decoded.userId,
                seedanceTask.content.video_url,
                {
                  taskId: video.task_id,
                  duration: video.duration,
                }
              );
              console.log(`[Video] 视频已存储到 TOS: ${tosKey}`);
              await VideoStorageService.setPublicRead(tosKey);

              // 如果有尾帧图片，也存储到 TOS
              if (seedanceTask.content.last_frame_url) {
                try {
                  lastFrameTosKey = await VideoStorageService.storeVideoFromUrl(
                    decoded.userId,
                    seedanceTask.content.last_frame_url,
                    { taskId: `${video.task_id}_last_frame` }
                  );
                  console.log(`[Video] 尾帧已存储到 TOS: ${lastFrameTosKey}`);
                } catch (frameError) {
                  console.error('[Video] 尾帧存储失败:', frameError);
                  // 尾帧存储失败不影响主流程
                }
              }
            } catch (tosError) {
              console.error('[Video] TOS 存储失败，使用临时 URL:', tosError);
              // 如果 TOS 存储失败，仍然使用临时 URL
            }

            const publicVideoUrl = tosKey
              ? VideoStorageService.getVideoPublicUrl(tosKey)
              : seedanceTask.content.video_url;

            // 更新数据库
            await supabase
              .from('videos')
              .update({
                status: 'completed',
                public_video_url: publicVideoUrl,
                result_url: publicVideoUrl,
                tos_key: tosKey,
                last_frame_url: seedanceTask.content.last_frame_url,
                last_frame_tos_key: lastFrameTosKey,
                cost,
                total_tokens: totalTokens,
              })
              .eq('id', video.id);
            if (video.session_id) {
              const workerTaskId = await findVideoWorkerTaskId(decoded.userId, String(video.id));
              if (workerTaskId) {
                await taskStateService.transitionTask(workerTaskId, 'succeeded', {
                  progress: 100,
                  completed_at: new Date().toISOString(),
                  output_data: {
                    video_id: video.id,
                    seedance_task_id: video.task_id,
                    public_video_url: publicVideoUrl,
                    tos_key: tosKey,
                  },
                });
                await taskStateService.appendEvent(workerTaskId, decoded.userId, String(video.session_id), 'video_generate_succeeded', {
                  video_id: video.id,
                  public_video_url: publicVideoUrl,
                });
              }
            }

            // 自动标签识别：只从标签池里挑选，未命中再走最小兜底
            try {
              const { data: defs } = await supabase
                .from('tag_definitions')
                .select('name')
                .eq('enabled', true)
                .order('name', { ascending: true });
              const pool = (defs || []).map((item: any) => item.name as string).filter(Boolean);
              const autoTags = deriveAutoTags({
                prompt: video.prompt,
                script: video.script,
                copywriting: video.copywriting,
                category: video.category,
                isRemix: Boolean(video.is_remix),
              }, pool);
              await supabase
                .from('videos')
                .update({
                  tags: autoTags,
                  tag_source: 'auto',
                  auto_tag_status: 'success',
                  updated_at: new Date().toISOString(),
                })
                .eq('id', video.id);
            } catch (tagError) {
              console.error('自动标签识别失败:', tagError);
              await supabase
                .from('videos')
                .update({
                  auto_tag_status: 'failed',
                  updated_at: new Date().toISOString(),
                })
                .eq('id', video.id);
            }

            // 记录账单
            await supabase.from('billing').insert({
              user_id: decoded.userId,
              video_id: video.id,
              amount: cost,
              token_amount: totalTokens,
              task_type: 'video_generation',
              description: `视频生成 - ${video.duration}秒 - ${video.ratio} - ${totalTokens.toLocaleString()} tokens`,
            });

            video.status = 'completed';
            video.public_video_url = publicVideoUrl;
            video.result_url = publicVideoUrl;
            video.tos_key = tosKey;
            video.cost = cost;
          } else if (seedanceTask.status === 'failed') {
            await supabase
              .from('videos')
              .update({
                status: 'failed',
                error_message: seedanceTask.error?.message || '视频生成失败',
              })
              .eq('id', video.id);
            if (video.session_id) {
              const workerTaskId = await findVideoWorkerTaskId(decoded.userId, String(video.id));
              if (workerTaskId) {
                await taskStateService.transitionTask(workerTaskId, 'failed', {
                  progress: 100,
                  completed_at: new Date().toISOString(),
                  error_message: seedanceTask.error?.message || '视频生成失败',
                  output_data: { video_id: video.id, seedance_task_id: video.task_id },
                });
                await taskStateService.appendEvent(workerTaskId, decoded.userId, String(video.session_id), 'video_generate_failed', {
                  video_id: video.id,
                  error: seedanceTask.error?.message || '视频生成失败',
                });
              }
            }

            video.status = 'failed';
            video.error_message = seedanceTask.error?.message;
          }
        } catch (pollError) {
          console.error('轮询 Seedance 任务失败:', pollError);
        }
      }

      return NextResponse.json({ video: data });
    } else {
      // 查询用户所有任务
      const { data, error } = await supabase
        .from('videos')
        .select('*')
        .eq('user_id', decoded.userId)
        .order('created_at', { ascending: false })
        .limit(50);

      if (error) {
        throw new Error(`查询失败: ${error.message}`);
      }

      return NextResponse.json({ videos: data });
    }
  } catch (error) {
    console.error('查询视频任务错误:', error);
    return NextResponse.json(
      { error: error instanceof Error ? error.message : '查询失败' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getSupabaseClient } from '@/storage/database/supabase-client';
