async function saveConversationMessage(
  userId: string,
  sessionId: string,
  role: 'user' | 'assistant',
  content: string,
  parts?: MessagePart[]
): Promise<string | null> {
  try {
    const supabase = getSupabaseClient();
    const { data: inserted } = await supabase
      .from('agent_conversation_messages')
      .insert({
        user_id: userId,
        session_id: sessionId,
        role: role,
        content: content,
        parts: Array.isArray(parts) && parts.length > 0 ? parts : null,
      })
      .select('id')
      .single();
    const now = new Date().toISOString();
    const { data: session } = await supabase
      .from('agent_sessions')
      .select('message_count')
      .eq('id', sessionId)
      .eq('user_id', userId)
      .single();
    const sessionData = (session || null) as { message_count?: number } | null;
    const nextCount = (sessionData?.message_count || 0) + 1;
    await supabase
      .from('agent_sessions')
      .update({
        last_message_at: now,
        message_count: nextCount,
      })
      .eq('id', sessionId)
      .eq('user_id', userId);
    console.log(`💾 [笔记本1号] 已保存 ${role} 消息`);
    return (inserted as { id?: string } | null)?.id || null;
  } catch (error) {
    console.error('❌ [笔记本1号] 保存消息失败:', error);
    return null;
  }
}

