              key={material.id}
              className="group relative rounded-lg border overflow-hidden"
            >
              <div className="aspect-square bg-muted">
                {material.thumbnail ? (
                  <img 
                    src={material.thumbnail} 
                    alt="" 
                    className="w-full h-full object-cover" 
