}

function getTaskTypeLabel(taskType?: string): string {
  const value = (taskType || '').trim();
  if (!value) return '创意对话任务';
  const labels: Record<string, string> = {
    creative_chat: '创意对话任务',
    video_generate: '视频生成任务',
    image_generate: '图片生成任务',
    batch_generate: '批量生成任务',
  };
  return labels[value] || value;
}

function getTaskStatusLabel(status: WorkerTaskItem['status']): string {
  const labels: Record<WorkerTaskItem['status'], string> = {
    queued: '排队中',
    running: '执行中',
    succeeded: '已完成',
    partial_succeeded: '部分完成',
    failed: '失败',
    cancelled: '已取消',
  };
  return labels[status];
}

function TaskRail({
  tasks,
  onRetry,
  onCancel,
  onOpen,
}: {
  tasks: WorkerTaskItem[];
  onRetry: (taskId: string) => void;
  onCancel: (taskId: string) => void;
  onOpen: (taskId: string) => void;
}) {
  if (!tasks.length) {
    return (
      <div className="text-center py-8 text-sm text-muted-foreground">
        <ListChecks className="w-8 h-8 mx-auto mb-2 opacity-50" />
        <p>暂无任务记录</p>
      </div>
    );
  }

  return (
    <div className="space-y-2">
      {tasks.slice(0, 12).map((task) => (
        <div key={task.id} className="rounded-lg border p-2 space-y-2">
          <div className="flex items-center justify-between gap-2">
            <p className="text-xs font-medium truncate">{getTaskTypeLabel(task.task_type)}</p>
            <Badge variant={task.status === 'failed' ? 'destructive' : 'outline'} className="text-[10px]">
              {getTaskStatusLabel(task.status)}
            </Badge>
          </div>
          <div className="h-1.5 w-full rounded bg-muted overflow-hidden">
            <div className="h-full bg-primary transition-all" style={{ width: `${Math.max(0, Math.min(task.progress || 0, 100))}%` }} />
          </div>
          {task.error_message ? (
            <p className="text-[11px] text-destructive line-clamp-2">{task.error_message}</p>
          ) : (
            <p className="text-[11px] text-muted-foreground line-clamp-1">{task.id.slice(0, 12)}</p>
          )}
          <div className="flex items-center gap-1">
            <Button
              size="sm"
              variant="outline"
              className="h-7 min-w-[46px] text-[11px] px-2 font-medium text-foreground"
              onClick={() => onOpen(task.id)}
            >
              查看
            </Button>
            {task.status === 'failed' || task.status === 'cancelled' ? (
              <Button size="sm" variant="secondary" className="h-6 text-[10px] px-2" onClick={() => onRetry(task.id)}>
                重试
              </Button>
            ) : null}
            {task.status === 'queued' || task.status === 'running' ? (
              <Button size="sm" variant="ghost" className="h-6 text-[10px] px-2" onClick={() => onCancel(task.id)}>
                取消
              </Button>
            ) : null}
          </div>
        </div>
      ))}
    </div>
  );
}

