        .eq('user_id', userId)
        .eq('status', 'active')
        .order('last_message_at', { ascending: false })
        .limit(1)
        .single();

      if (error && (error as any).code !== 'PGRST116') {
        console.error('获取会话失败:', error);
        return { success: false, error: (error as any).message || '获取失败' };
      }

      // 如果没有活跃会话，创建一个新会话
      if (!session) {
