   * 用于将视频同步到学习库（分析并保存）
   * 参数：
   * - video_url: 视频URL
   * - video_name: 视频名称（可选）
   */
  async syncToLibrary(params: {
    video_url: string;
    video_name?: string;
  }): Promise<{
    success: boolean;
    data?: {
      library_id: string;
      video_name: string;
      status: string;
    };
    error?: string;
  }> {
    try {
      const userId = this.getUserId();
      const { video_url, video_name } = params;

      // 检查是否已存在
      const { data: existing } = await this.supabase
        .from('learning_library')
        .select('id')
        .eq('user_id', userId)
        .eq('video_url', video_url)
        .single();

      if (existing) {
        const e = existing as any;
        return {
          success: true,
          data: {
            library_id: e.id as string,
            video_name: video_name || '已存在的视频',
            status: 'already_exists'
          }
        };
      }

      // 插入新记录
      const { data, error } = await this.supabase
        .from('learning_library')
        .insert({
          user_id: userId,
          video_name: video_name || '未命名视频',
          video_url: video_url,
          analysis_status: 'pending'
        })
        .select('id')
        .single();

      if (error) {
        console.error('同步到学习库失败:', error);
        return { success: false, error: (error as any).message || '同步失败' };
      }

      console.log('已同步视频到学习库:', (data as any)?.id);
      return {
        success: true,
        data: {
          library_id: (data as any)?.id as string,
          video_name: video_name || '未命名视频',
          status: 'synced'
        }
      };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : '同步失败'
      };
    }
  }

