    const client = getSupabaseClient();

    const { data, error } = await client
      .from('creative_workflows')
      .insert({
        user_id: userId,
        session_id: sessionId,
        current_stage: 'input_collecting',
        status: 'active',
        input_content: {},
        reference_materials: [],
        script_version: 1,
