        video_iterations: [],
        selected_directions: [],
        batch_count: 0,
        batch_results: [],
        learned_preferences: {},
      })
      .select()
      .single();

    if (error) {
      throw new Error(`创建工作流失败: ${(error as any).message || '创建失败'}`);
