  ): Promise<{
    response: string;
    stage: WorkflowStage;
    requiresAction: boolean;
    actionType?: string;
    selectedDirections?: string[];
  }> {
    const client = getSupabaseClient();

    // 尝试解析用户选择的方向
    const selectedIds = this.parseDirectionSelection(message, workflow.batch_directions || []);

    if (selectedIds.length > 0) {
