    // 用户可能想看更多说明或调整方向
    const response = '您可以：\n1. 选择感兴趣的方向（例如"选择1、3、5"）\n2. 调整某个方向（例如"把第2个改成更暗的色调"）\n3. 直接告诉我您的想法';
    await this.saveMessage(workflow.id, 'assistant', response);

    return {
