  // ========== 定时任务工具实现 ==========

  private async createScheduledTask(params: Record<string, unknown>) {
    const taskName = params.task_name as string;
    const taskType = params.task_type as string;
    const cronExpression = params.cron_expression as string;
    const taskParams = params.params as string | undefined;

    // 解析 cron 表达式计算下次执行时间（简化版）
    const nextRun = this.calculateNextRun(cronExpression);

    const { data, error } = await this.supabase
      .from('finance_scheduled_tasks')
      .insert({
        user_id: this.userId,
        task_name: taskName,
        task_type: taskType,
        cron_expression: cronExpression,
        params: taskParams,
        next_run_at: nextRun,
        status: 'active',
      })
      .select()
      .single();

    if (error) throw new Error(`创建任务失败: ${(error as any).message}`);
    if (!data) throw new Error('创建任务失败：未返回数据');

    return {
      success: true,
      data: {
        taskId: (data as any).id as string,
        taskName,
        taskType,
        cronExpression,
        nextRunAt: nextRun,
      },
      message: `定时任务 "${taskName}" 创建成功，下次执行: ${nextRun}`
    };
  }

  private async getScheduledTasks() {
    const { data, error } = await this.supabase
      .from('finance_scheduled_tasks')
      .select('*')
      .eq('user_id', this.userId)
      .eq('status', 'active')
      .order('next_run_at', { ascending: true });

    if (error) throw new Error(`查询任务失败: ${error.message}`);

    return {
      success: true,
      data: {
        tasks: data?.map(t => ({
          taskId: t.id,
          taskName: t.task_name,
          taskType: t.task_type,
          cronExpression: t.cron_expression,
          nextRunAt: t.next_run_at,
          status: t.status,
        })) || [],
      },
      message: `查询到 ${data?.length || 0} 个定时任务`
    };
  }

  private async deleteScheduledTask(params: Record<string, unknown>) {
    const taskId = params.task_id as string;

    const { error } = await this.supabase
      .from('finance_scheduled_tasks')
      .update({ status: 'deleted' })
      .eq('id', taskId)
      .eq('user_id', this.userId);

    if (error) throw new Error(`删除任务失败: ${error.message}`);

    return {
      success: true,
      message: '定时任务已删除'
    };
  }

  private calculateNextRun(cronExpression: string): string {
    // 简化版 cron 解析
    const now = new Date();
    const parts = cronExpression.split(' ');

    // 支持简单格式: 分 时 日 月 周
    // 例如: "0 9 * * *" = 每天9点
    // "0 9 * * 1" = 每周一9点

    if (parts.length >= 5) {
      const [minute, hour, , , dayOfWeek] = parts;

      // 计算下次执行时间
      const next = new Date(now);

      if (hour !== '*') {
        next.setHours(parseInt(hour), parseInt(minute) || 0, 0, 0);
        if (next <= now) {
          next.setDate(next.getDate() + 1);
        }
      } else {
        next.setTime(next.getTime() + 60 * 60 * 1000); // 默认1小时后
      }

      return next.toISOString();
    }

    // 默认1小时后
    return new Date(now.getTime() + 60 * 60 * 1000).toISOString();
  }

  // ========== 预算管理工具实现 ==========

  private async setBudgetAlert(params: Record<string, unknown>) {
    const budgetAmount = params.budget_amount as number;
    const periodType = params.period_type as string;
    const alertThreshold = (params.alert_threshold as number) || 0.8;

    const { data, error } = await this.supabase
      .from('finance_scheduled_tasks')
      .upsert({
        user_id: this.userId,
        task_name: `${periodType} 预算提醒`,
        task_type: 'budget_alert',
        cron_expression: periodType === 'monthly' ? '0 9 1 * *' : periodType === 'weekly' ? '0 9 * * 1' : '0 9 * * *',
        params: JSON.stringify({ budget_amount: budgetAmount, alert_threshold: alertThreshold }),
        status: 'active',
      })
      .select()
      .single();

    if (error) throw new Error(`设置预算失败: ${error.message}`);

    return {
      success: true,
      data: {
        budgetAmount,
        periodType,
        alertThreshold,
        taskId: data?.id,
      },
      message: `预算提醒设置成功: ${budgetAmount}元/${periodType}`
    };
  }

  private async getBudgetStatus() {
    // 查询当前消费
    const { data: bills } = await this.supabase
      .from('billing')
      .select('amount, created_at')
      .gte('created_at', new Date(new Date().setDate(1)).toISOString());

    const totalSpend = bills?.reduce((sum, b) => sum + formatAmount(b.amount), 0) || 0;

    // 查询预算设置
    const { data: budgets } = await this.supabase
      .from('finance_scheduled_tasks')
      .select('*')
      .eq('user_id', this.userId)
      .eq('task_type', 'budget_alert')
      .eq('status', 'active');

    const b = (budgets as any[])?.[0];
    let budgetAmount = 0;
    let alertThreshold = 0.8;

    if (b?.params) {
      try {
        const params = JSON.parse(b.params as string);
        budgetAmount = params.budget_amount || 0;
        alertThreshold = params.alert_threshold || 0.8;
      } catch {}
    }

    return {
      success: true,
      data: {
        totalSpend: Math.round(totalSpend * 100) / 100,
        budgetAmount,
        remaining: Math.round((budgetAmount - totalSpend) * 100) / 100,
        percentage: budgetAmount > 0 ? Math.round((totalSpend / budgetAmount) * 100) : 0,
        alertThreshold,
        isOverBudget: totalSpend > budgetAmount && budgetAmount > 0,
        isNearBudget: budgetAmount > 0 && (totalSpend / budgetAmount) >= alertThreshold,
      },
      message: budgetAmount > 0 
        ? `本月已消费 ${totalSpend.toFixed(2)}元，预算 ${budgetAmount}元`
        : '暂无预算设置'
    };
  }

  // ========== 联网搜索工具实现 ==========

  private async executeWebSearch(params: Record<string, unknown>) {
    // 如果联网未开启，返回提示
    if (!this.webSearchEnabled) {
      return {
        success: false,
        error: '联网搜索功能未开启，请在界面右上角开启联网模式'
      };
    }

    const query = (params.query as string) || '';
    const count = (params.count as number) || 5;

    if (!query) {
      return {
        success: false,
        error: '搜索关键词不能为空'
      };
    }

    try {
      const result = await this.searchClient.webSearch(query, count);

      if (result.web_items && result.web_items.length > 0) {
        const resultText = result.web_items
          .map((r: any, i: number) => `${i + 1}. 【${r.title}】\n   ${r.snippet}\n   来源: ${r.site_name || '未知网站'}`)
          .join('\n\n');

        return {
          success: true,
          data: {
            summary: result.summary || '',
            results: result.web_items,
            formatted: `--- 联网搜索结果（${result.web_items.length}条）---\n${result.summary ? result.summary + '\n\n' : ''}${resultText}`
          },
          message: `搜索到 ${result.web_items.length} 条相关结果`
        };
      } else {
        return {
          success: false,
          error: '未找到相关结果'
        };
      }
    } catch (error) {
      console.error('[Finance] 联网搜索失败:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : '联网搜索失败'
      };
    }
  }
}

/**
 * 图片分析服务
 * 
 * 使用 LLM 视觉能力分析商品图片
 */

import { LLMClient, Config } from 'coze-coding-dev-sdk';

const client = new LLMClient(new Config());

// ========== 类型定义 ==========

export interface VisualFeatures {
  colors: string[];           // 主色调列表
  scene: string;             // 拍摄场景
  light_style: string;       // 光影风格
  angle: string;             // 展示角度
  packaging_style?: string;   // 包装风格
}

export interface KeySellingPoint {
  content: string;           // 卖点内容
  source: 'text_extract' | 'visual_infer';  // 来源
}

export interface ImageAnalysisResult {
  product_name: string;      // 产品名称
  category: string;           // 产品品类
  visual_features: VisualFeatures;
  is_contains_people: boolean;  // 是否含有人脸
  key_selling_points: KeySellingPoint[];  // 卖点
  text_content: string;       // 图片文字
  suggested_scenes: string[]; // 推荐场景
  confidence: {
    overall: number;
    product_name: number;
    category: number;
    selling_points: number;
  };
  source_image?: string;      // 来源图片
}

export interface MultiImageAnalysisResult {
  aggregated: ImageAnalysisResult;  // 聚合结果
  individual: ImageAnalysisResult[];  // 单图结果
}

// ========== 通用分析 Prompt ==========

const BASE_PROMPT = `分析这张商品图片，提取以下信息，以 JSON 格式输出：

{
  "product_name": "产品名称（无法识别返回空字符串）",
  "category": "产品品类（尽量细分，如'美妆/面部精华'、'食品/饮料'、'数码/蓝牙耳机'）",
  "visual_features": {
    "colors": ["主色调列表，最多3个"],
    "scene": "拍摄场景（如'静物台'、'生活场景'、'户外自然'）",
    "light_style": "光影风格（如'柔光'、'硬光'、'自然光'、'暖光'）",
    "angle": "展示角度（如'正面平视'、'45度俯视'、'侧面特写'）",
    "packaging_style": "包装风格（如'简约ins风'、'国潮古风'、'科技感'、'轻奢风'）"
  },
  "is_contains_people": true或false，检测图片是否含有人脸
  "key_selling_points": [
    {
      "content": "卖点内容",
      "source": "text_extract表示从图片文字提取，visual_infer表示视觉推断"
    }
  ],
  "text_content": "图片上的文字内容（如果没有则返回空字符串）",
  "suggested_scenes": ["推荐视频场景1", "推荐视频场景2"]，
  "confidence": {
    "overall": 0.0-1.0的整体可信度，
    "product_name": 0.0-1.0的产品名称识别可信度，
    "category": 0.0-1.0的品类识别可信度，
    "selling_points": 0.0-1.0的卖点识别可信度
  }
}

要求：
- 严格按照 JSON 格式输出，不要添加额外解释
- 所有字段都需要返回
- 如果无法识别某项，返回空值或默认值
- is_contains_people 如果检测到任何人脸元素，返回 true`;

// ========== 品类专属 Prompt ==========

const CATEGORY_PROMPTS: Record<string, string> = {
  '美妆': `\n\n针对美妆品类，额外关注：
- 质地类型（精华液、乳霜、粉状、膏体等）
- 包装设计特点（泵头、按压式、滴管、软管等）
- 是否有特殊成分标识（如玻尿酸、烟酰胺等）
- 产品形态（单个、礼盒、组合装）`,

  '食品': `\n\n针对食品品类，额外关注：
- 食材类型和口味标注
- 食用场景（早餐、零食、正餐、聚会等）
- 包装上的促销信息或卖点
- 生产日期/保质期相关信息（不要写入卖点）`,

  '数码': `\n\n针对数码品类，额外关注：
- 产品具体形态（入耳式、头戴式、便携式等）
- 材质质感（金属、塑料、玻璃等）
- 接口类型和数量
