};

// ========== 图片分析服务 ==========

export class ImageAnalysisService {
  /**
   * 分析单张图片
   */
  async analyzeImage(
    imageUrl: string,
    categoryHint?: string
  ): Promise<{
    success: boolean;
    data?: ImageAnalysisResult;
    error?: string;
  }> {
    try {
      const llmClient = new LLMClient(new Config());

      // 构建 Prompt
      let prompt = BASE_PROMPT;
      if (categoryHint) {
        // 根据品类添加专属 Prompt
        for (const [key, suffix] of Object.entries(CATEGORY_PROMPTS)) {
          if (categoryHint.includes(key)) {
            prompt += suffix;
            break;
          }
        }
      }

      // 构建包含图片的多模态消息
      const messages = [
        {
          role: 'user' as const,
          content: [
            { type: 'text' as const, text: prompt },
            {
              type: 'image_url' as const,
              image_url: { url: imageUrl },
            },
          ],
        },
      ];

      // 使用 stream 方法
      const stream = llmClient.stream(messages, {
        model: 'doubao-seed-1-6-vision-250815',
        temperature: 0.3,
      });

      let fullResponse = '';
      for await (const chunk of stream) {
        if (chunk.content) {
          fullResponse += chunk.content.toString();
        }
      }

      if (!fullResponse) {
        return { success: false, error: '分析失败，未返回结果' };
      }

      // 提取 JSON
      const jsonMatch = fullResponse.match(/\{[\s\S]*\}/);
      if (!jsonMatch) {
        return { success: false, error: '无法解析分析结果' };
      }

      const parsed = JSON.parse(jsonMatch[0]);

      return {
        success: true,
        data: {
          product_name: parsed.product_name || '',
          category: parsed.category || '',
          visual_features: {
            colors: parsed.visual_features?.colors || [],
            scene: parsed.visual_features?.scene || '',
            light_style: parsed.visual_features?.light_style || '',
            angle: parsed.visual_features?.angle || '',
            packaging_style: parsed.visual_features?.packaging_style || ''
          },
          is_contains_people: parsed.is_contains_people || false,
          key_selling_points: (parsed.key_selling_points || []).map((p: any) => ({
            content: p.content || '',
            source: p.source === 'text_extract' ? 'text_extract' : 'visual_infer'
          })),
          text_content: parsed.text_content || '',
          suggested_scenes: parsed.suggested_scenes || [],
          confidence: {
            overall: parsed.confidence?.overall || 0.5,
            product_name: parsed.confidence?.product_name || 0.5,
            category: parsed.confidence?.category || 0.5,
            selling_points: parsed.confidence?.selling_points || 0.5
          },
          source_image: imageUrl
        } as ImageAnalysisResult
      };

    } catch (error) {
      console.error('图片分析失败:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : '分析失败'
      };
    }
  }

  /**
   * 分析多张图片并聚合结果
   */
  async analyzeMultipleImages(
    imageUrls: string[],
    categoryHint?: string
  ): Promise<{
    success: boolean;
    data?: MultiImageAnalysisResult;
    error?: string;
  }> {
    try {
      // 并行分析每张图片
      const results = await Promise.all(
        imageUrls.map(url => this.analyzeImage(url, categoryHint))
      );

      // 过滤成功的结果
      const successfulResults = results
        .filter(r => r.success && r.data)
        .map(r => r.data!);

      if (successfulResults.length === 0) {
        return { success: false, error: '所有图片分析均失败' };
      }

      // 聚合结果
      const aggregated = this.aggregateResults(successfulResults);

      return {
        success: true,
        data: {
          aggregated,
          individual: successfulResults
        }
      };

    } catch (error) {
      console.error('多图分析失败:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : '多图分析失败'
      };
    }
  }

  /**
   * 聚合多张图片的分析结果
   */
  private aggregateResults(results: ImageAnalysisResult[]): ImageAnalysisResult {
    if (results.length === 1) {
      return results[0];
    }

    // 取可信度最高的产品名称
    const productNameResult = results.reduce((best, current) => 
      current.confidence.product_name > best.confidence.product_name ? current : best
    );

    // 取可信度最高的品类
    const categoryResult = results.reduce((best, current) => 
      current.confidence.category > best.confidence.category ? current : best
    );

    // 合并颜色（去重）
    const allColors = new Set<string>();
    results.forEach(r => r.visual_features.colors.forEach(c => allColors.add(c)));

    // 合并卖点
    const allSellingPoints = new Map<string, KeySellingPoint>();
    results.forEach(r => {
      r.key_selling_points.forEach(p => {
        if (!allSellingPoints.has(p.content)) {
          allSellingPoints.set(p.content, p);
        }
      });
    });

    // 检查是否含人脸
    const containsPeople = results.some(r => r.is_contains_people);

    // 合并推荐场景
    const allScenes = new Set<string>();
    results.forEach(r => r.suggested_scenes.forEach(s => allScenes.add(s)));

    // 合并文字内容
    const allTexts = results
      .map(r => r.text_content)
      .filter(t => t)
      .join('; ');

    return {
      product_name: productNameResult.product_name,
      category: categoryResult.category,
      visual_features: {
        colors: Array.from(allColors).slice(0, 3),
        scene: results[0].visual_features.scene,
        light_style: results[0].visual_features.light_style,
        angle: results[0].visual_features.angle,
        packaging_style: results[0].visual_features.packaging_style
      },
      is_contains_people: containsPeople,
      key_selling_points: Array.from(allSellingPoints.values()),
      text_content: allTexts,
      suggested_scenes: Array.from(allScenes),
      confidence: {
        overall: results.reduce((sum, r) => sum + r.confidence.overall, 0) / results.length,
        product_name: productNameResult.confidence.product_name,
        category: categoryResult.confidence.category,
        selling_points: results.reduce((sum, r) => sum + r.confidence.selling_points, 0) / results.length
      }
    };
  }

  /**
   * 从分析结果生成脚本推荐
   */
  generateScriptSuggestions(result: ImageAnalysisResult, count: number = 3): string[] {
    const suggestions: string[] = [];
    const features = result.visual_features;

    for (let i = 0; i < count; i++) {
      const style = i === 0 ? '产品特写展示' : i === 1 ? '场景融入展示' : '综合卖点展示';
      const scene = result.suggested_scenes[i % result.suggested_scenes.length] || features.scene;

      suggestions.push(
        `${style}风格：${features.light_style}光影，${features.angle}角度，` +
        `场景为${scene}，包装风格${features.packaging_style || '简约'}，` +
        `核心卖点：${result.key_selling_points.slice(0, 2).map(p => p.content).join('、') || '产品展示'}`
      );
    }

    return suggestions;
  }
}

export default ImageAnalysisService;

/**
 * 图片生成服务
 * 使用豆包 SeeDream 模型生成高质量图片
 * 
 * 核心能力：
 * 1. 文生图 (text-to-image)
 * 2. 图生图 (image-to-image) - 用于首帧图生成
 * 3. 支持 2K/4K 尺寸
 */

import { ImageGenerationClient, Config } from 'coze-coding-dev-sdk';
import { LearningLibraryStorage, VideoStorageService } from './tos-storage';
import { getSupabaseClient } from '@/storage/database/supabase-client';

export interface GenerateFirstFrameRequest {
  productImageUrl?: string;   // 商品图片 URL（可选，支持纯文生图）
  scriptContent?: string;     // 脚本描述（用于生成首帧场景）
  prompt?: string;            // 直接提示词（优先于脚本描述）
  aspectRatio?: string;      // 视频比例 9:16 或 16:9
  style?: string;            // 风格描述
  referenceStyle?: string;   // 参考视频风格
}

export interface GenerateFirstFrameResult {
  success: boolean;
  imageUrl?: string;
  publicImageUrl?: string;
  signedImageUrl?: string;
  imageId?: string;
  key?: string;
  error?: string;
}

export class ImageGenerationService {
  private client: ImageGenerationClient;
  // 延迟初始化，避免构建时检查环境变量
  private _supabase: ReturnType<typeof getSupabaseClient> | null = null;

  constructor() {
    const config = new Config();
    this.client = new ImageGenerationClient(config);
  }

  private get supabase() {
    if (!this._supabase) {
      this._supabase = getSupabaseClient();
    }
    return this._supabase;
  }

  /**
   * 生成首帧图 ⭐ 核心功能
   * 
   * 根据商品图和脚本描述，生成符合视频开头场景的首帧图
   * 支持图生图模式，让生成的首帧图保持商品特征
   */
  async generateFirstFrame(request: GenerateFirstFrameRequest): Promise<GenerateFirstFrameResult> {
    try {
      const {
        productImageUrl,
        scriptContent = '',
        prompt,
        aspectRatio = '9:16',
        style,
        referenceStyle,
      } = request;

      console.log('[首帧图生成] 开始生成:', {
        productImageUrl,
        scriptContent: scriptContent.substring(0, 100),
        hasPrompt: Boolean(prompt),
        aspectRatio
      });

      // 构建提示词
      const finalPrompt: string =
        typeof prompt === 'string' && prompt.trim().length > 0
          ? prompt.trim()
          : this.buildFirstFramePrompt(scriptContent, style, referenceStyle);

      // 确定尺寸
      const size = aspectRatio === '9:16' ? '2K' : '2K';

      // 调用图片生成 API（支持文生图/图生图）
      const response = await this.client.generate({
        prompt: finalPrompt,
        size,
        image: productImageUrl || undefined,  // 有图则图生图，无图则文生图
        watermark: false,
      });

      // 获取结果
      const helper = this.client.getResponseHelper(response);

      if (!helper.success || !helper.imageUrls || helper.imageUrls.length === 0) {
        console.error('[首帧图生成] 生成失败:', helper);
        return {
          success: false,
          error: helper.errorMessages?.[0] || '生成失败'
        };
      }

      const imageUrl = helper.imageUrls[0];
      console.log('[首帧图生成] 生成成功:', imageUrl);

      // 下载图片并上传到 TOS
      const localPath = await this.downloadImage(imageUrl);
      const tosKey = await this.uploadToTOS(localPath, `first_frame_${Date.now()}.png`);
      const signedUrl = await LearningLibraryStorage.getLearningVideoUrl(tosKey);
      const publicReadable = await VideoStorageService.setPublicRead(tosKey);
      const publicUrl = publicReadable ? VideoStorageService.getPublicUrl(tosKey) : signedUrl;

      // 保存到数据库
      const imageId = await this.saveToDatabase(tosKey, publicUrl, finalPrompt);

      return {
        success: true,
        imageUrl: publicUrl,
        publicImageUrl: publicUrl,
        signedImageUrl: signedUrl,
        imageId,
        key: tosKey
      };

    } catch (error) {
      console.error('[首帧图生成] 错误:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : '生成失败'
      };
    }
  }

  /**
   * 构建首帧图提示词
   */
  private buildFirstFramePrompt(
    scriptContent: string,
    style?: string,
    referenceStyle?: string
  ): string {
    // 提取脚本中的场景描述
    const sceneMatch = scriptContent.match(/【.*?】(.+?)(?=【|口播|$)/g);
    const scenes = sceneMatch?.map(s => s.replace(/【.*?】/, '').trim()).join(', ') || scriptContent;

    // 构建提示词
    let prompt = `First frame of a product video: ${scenes}`;

    if (style) {
      prompt += `. Style: ${style}`;
    }

    if (referenceStyle) {
      prompt += `. Reference style: ${referenceStyle}`;
    }

    // 添加 Seedance 友好的描述
    prompt += `. High quality product photography, soft lighting, clean background, professional commercial style.`;

    // 禁止元素
    prompt += ` . No text, no logos, no watermarks, no realistic human faces.`;

    return prompt;
  }

  /**
   * 下载图片到本地
   */
  private async downloadImage(url: string): Promise<string> {
    const path = `/tmp/first_frame_${Date.now()}.png`;

    const response = await fetch(url);
    const buffer = await response.arrayBuffer();

    const fs = await import('fs/promises');
    await fs.writeFile(path, Buffer.from(buffer));

    return path;
  }

  /**
   * 上传到 TOS
   */
  private async uploadToTOS(localPath: string, fileName: string): Promise<string> {
    const fs = await import('fs/promises');
    const buffer = await fs.readFile(localPath);

    // 使用学习库存储
    const key = await LearningLibraryStorage.uploadLearningVideo(
      'system', // 系统文件
      buffer,
      fileName,
      'image/png'
    );

    // 清理本地文件
    await fs.unlink(localPath).catch(() => {});

    return key;
  }

  /**
   * 保存到数据库
   */
  private async saveToDatabase(key: string, url: string, prompt: string): Promise<string> {
    const imageId = `img_${Date.now()}`;

    // 保存到 uploaded_files 表
    const { error } = await this.supabase
      .from('uploaded_files')
      .insert({
        file_id: imageId,
        file_name: `首帧图_${Date.now()}`,
        file_type: 'image',
        file_url: url,
        tos_key: key,
        file_size: 0,
        created_by: 'system'
      });

    if (error) {
      console.warn('[首帧图保存] 数据库保存失败:', error);
    }

    return imageId;
  }

  /**
   * 通用图片生成
   */
  async generateImage(
    prompt: string,
    options?: {
      size?: '2K' | '4K';
      image?: string;  // 参考图
      style?: string;
    }
  ): Promise<{
    success: boolean;
    imageUrl?: string;
    error?: string;
  }> {
    try {
      const response = await this.client.generate({
        prompt,
        size: options?.size || '2K',
        image: options?.image,
        watermark: false,
      });

      const helper = this.client.getResponseHelper(response);

      if (!helper.success || !helper.imageUrls) {
        return {
          success: false,
          error: helper.errorMessages?.[0] || '生成失败'
        };
      }

      return {
        success: true,
        imageUrl: helper.imageUrls[0]
      };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : '生成失败'
      };
    }
  }
}

