/**
 * 记忆分层服务
 * 基于虾评Skill的记忆系统设计
 * 
 * 记忆分层：
 * 1. SESSION-STATE - 当前任务恢复层（保存中断后续接所需的最小真相）
 * 2. WORKING-BUFFER - 毛坯区（放临时判断、草稿和待蒸馏内容）
 * 3. LONG-TERM-MEMORY - 蒸馏后的长期记忆（保存稳定偏好、约定、决策）
 * 4. DAILY-NOTES - 每日笔记和原始过程记录
 * 
 * 核心原则：文件是唯一的真相源
 */

import { getSupabaseClient } from '@/storage/database/supabase-client';
import { LLMClient, Config } from 'coze-coding-dev-sdk';

// 记忆层级
export enum MemoryLayer {
  SESSION_STATE = 'session_state',     // 当前任务恢复
  WORKING_BUFFER = 'working_buffer',   // 毛坯区
  LONG_TERM_MEMORY = 'long_term',      // 长期记忆
  DAILY_NOTE = 'daily_note',           // 每日笔记
}

// 记忆条目状态
export enum MemoryStatus {
  DRAFT = 'draft',           // 草稿
  PENDING = 'pending',       // 待蒸馏
  DISTILLED = 'distilled',   // 已蒸馏
  ARCHIVED = 'archived',     // 已归档
}

// 记忆条目接口
export interface MemoryEntry {
  id?: string;
  userId: string;
  layer: MemoryLayer;
  status: MemoryStatus;
  title: string;
  content: string;
  summary?: string;
  keywords?: string[];
  importanceScore?: number;
  parentMemoryId?: string;  // 关联的父记忆
  sessionContext?: Record<string, unknown>;  // 会话上下文
  distilledFrom?: string[];  // 从哪些条目蒸馏而来
  createdAt?: Date;
  updatedAt?: Date;
}

// 会话状态接口
export interface SessionState {
  currentTask?: string;
  completed: string[];
  blockers: string[];
  nextSteps: string[];
  recoveryInfo?: string;
}

/**
 * 记忆分层服务类
 */
export class MemoryLayerService {
  private headers: Record<string, string>;

  constructor(headers?: Record<string, string>) {
    this.headers = headers || {};
  }

  // ==================== 会话状态管理 ====================

  /**
   * 保存当前会话状态
   */
  async saveSessionState(userId: string, state: SessionState): Promise<void> {
    const client = getSupabaseClient();

    // 查找现有会话状态
    const { data: existing } = await client
      .from('agent_memories')
      .select('id')
      .eq('user_id', userId)
      .eq('layer', MemoryLayer.SESSION_STATE)
      .eq('status', MemoryStatus.DRAFT)
      .single();

    const content = JSON.stringify(state, null, 2);
    const title = `会话状态 - ${new Date().toLocaleDateString()}`;

    if (existing) {
      await client
        .from('agent_memories')
        .update({
          content,
          title,
          session_context: state,
          updated_at: new Date().toISOString(),
        })
        .eq('id', existing.id);
    } else {
      await client
        .from('agent_memories')
        .insert({
          user_id: userId,
          layer: MemoryLayer.SESSION_STATE,
          status: MemoryStatus.DRAFT,
          title,
          content,
          session_context: state,
          importance_score: 0.9,
        });
    }
  }

  /**
   * 恢复会话状态
   */
  async restoreSessionState(userId: string): Promise<SessionState | null> {
    const client = getSupabaseClient();

    const { data: memory } = await client
      .from('agent_memories')
      .select('session_context, updated_at')
      .eq('user_id', userId)
      .eq('layer', MemoryLayer.SESSION_STATE)
      .order('updated_at', { ascending: false })
      .single();

    if (memory?.session_context) {
      return memory.session_context as SessionState;
    }

    return null;
  }

  // ==================== 工作缓冲区管理 ====================

  /**
   * 添加到工作缓冲区
   */
  async addToWorkingBuffer(params: {
    userId: string;
    title: string;
    content: string;
    keywords?: string[];
  }): Promise<string> {
    const client = getSupabaseClient();

    const { data, error } = await client
      .from('agent_memories')
      .insert({
        user_id: params.userId,
        layer: MemoryLayer.WORKING_BUFFER,
        status: MemoryStatus.DRAFT,
        title: params.title,
        content: params.content,
        keywords: params.keywords,
        importance_score: 0.5,
      })
      .select('id')
      .single();

    if (error) {
      throw new Error(`添加到工作缓冲区失败: ${(error as any).message}`);
    }
    if (!data) {
      throw new Error('添加到工作缓冲区失败：未返回数据');
    }

    return (data as any).id as string;
  }

  /**
   * 获取工作缓冲区内容
   */
  async getWorkingBuffer(userId: string, limit: number = 10): Promise<MemoryEntry[]> {
    const client = getSupabaseClient();

    const { data, error } = await client
      .from('agent_memories')
      .select('*')
      .eq('user_id', userId)
      .eq('layer', MemoryLayer.WORKING_BUFFER)
      .order('created_at', { ascending: false })
      .limit(limit);

    if (error) {
      return [];
    }

    return (data || []) as unknown as MemoryEntry[];
  }

  // ==================== 长期记忆管理 ====================

  /**
   * 蒸馏工作缓冲区到长期记忆
   */
  async distillToLongTermMemory(params: {
    userId: string;
    bufferIds?: string[];  // 指定要蒸馏的条目，不指定则处理所有待蒸馏条目
  }): Promise<string[]> {
    const client = getSupabaseClient();

    // 获取待蒸馏的内容
    let query = client
      .from('agent_memories')
      .select('*')
      .eq('user_id', params.userId)
      .eq('layer', MemoryLayer.WORKING_BUFFER)
      .eq('status', MemoryStatus.PENDING);

    if (params.bufferIds && params.bufferIds.length > 0) {
      query = query.in('id', params.bufferIds);
    }

    const { data: bufferItems } = await query;

    if (!bufferItems || bufferItems.length === 0) {
      return [];
    }

    const distilledIds: string[] = [];

    // 批量蒸馏
    for (const item of bufferItems as any[]) {
      try {
        // 使用 LLM 蒸馏内容
        const distilledContent = await this.distillContent(item.content as string, item.title as string);

        // 创建长期记忆
        const { data: longTermMemory, error: insertError } = await client
          .from('agent_memories')
          .insert({
            user_id: params.userId,
            layer: MemoryLayer.LONG_TERM_MEMORY,
            status: MemoryStatus.DISTILLED,
            title: distilledContent.title,
            content: distilledContent.content,
            summary: distilledContent.summary,
            keywords: distilledContent.keywords,
            importance_score: 0.8,
            distilled_from: [item.id],
          })
          .select('id')
          .single();

        if (!insertError && longTermMemory) {
          // 标记原条目为已蒸馏
          await client
            .from('agent_memories')
            .update({
              status: MemoryStatus.DISTILLED,
              parent_memory_id: (longTermMemory as any).id,
            })
            .eq('id', item.id as string);

          distilledIds.push((longTermMemory as any).id as string);
        }
      } catch (e) {
        console.error(`蒸馏失败 [${item.id}]:`, e);
      }
    }

    return distilledIds;
  }

  /**
   * 蒸馏内容
   */
  private async distillContent(content: string, title: string): Promise<{
    title: string;
    content: string;
    summary: string;
    keywords: string[];
  }> {
    const llmClient = new LLMClient(new Config(), this.headers);

    const systemPrompt = `你是一位知识蒸馏专家。你的任务是将原始笔记提炼成稳定、持久的知识。

蒸馏原则：
1. 提取核心事实和决策
2. 移除临时性、过程性的内容
3. 保留可复用的知识和模式
4. 使用简洁、准确的语言

请返回 JSON 格式的蒸馏结果。`;

    const userPrompt = `请蒸馏以下内容：

标题：${title}
内容：
${content}

返回 JSON 格式：
{
  "title": "蒸馏后的标题",
  "content": "蒸馏后的内容",
  "summary": "一句话摘要",
  "keywords": ["关键词1", "关键词2", "关键词3"]
}`;

    try {
      let fullResponse = '';
      for await (const chunk of llmClient.stream([
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt },
      ], { model: 'doubao-seed-1-8-251228', temperature: 0.3 })) {
        if (chunk.content) {
          fullResponse += chunk.content.toString();
        }
      }

      const jsonMatch = fullResponse.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
    } catch (e) {
      console.error('蒸馏内容失败:', e);
    }

    // 返回原始内容
    return {
      title,
      content,
      summary: content.slice(0, 100),
      keywords: [],
    };
  }

  /**
   * 获取长期记忆
   */
  async getLongTermMemories(userId: string, limit: number = 20): Promise<MemoryEntry[]> {
    const client = getSupabaseClient();

    const { data, error } = await client
      .from('agent_memories')
      .select('*')
      .eq('user_id', userId)
      .eq('layer', MemoryLayer.LONG_TERM_MEMORY)
      .order('importance_score', { ascending: false })
      .order('updated_at', { ascending: false })
      .limit(limit);

    if (error) {
      return [];
    }

    return (data || []) as unknown as MemoryEntry[];
  }

  // ==================== 每日笔记管理 ====================

  /**
   * 创建每日笔记
   */
  async createDailyNote(params: {
    userId: string;
    content: string;
    tags?: string[];
  }): Promise<string> {
    const client = getSupabaseClient();

    const today = new Date().toISOString().split('T')[0];
    const title = `每日笔记 - ${today}`;

    // 检查今天是否已有笔记
    const { data: existing } = await client
      .from('agent_memories')
      .select('id, content')
      .eq('user_id', params.userId)
      .eq('layer', MemoryLayer.DAILY_NOTE)
      .eq('title', title)
      .single();

    if (existing) {
      // 追加到现有笔记
      const existingAny = existing as any;
      const newContent = (existingAny.content as string) + '\n\n---\n\n' + params.content;
      await client
        .from('agent_memories')
        .update({ content: newContent })
        .eq('id', existingAny.id);
      return existingAny.id as string;
    }

    // 创建新笔记
    const { data, error } = await client
      .from('agent_memories')
      .insert({
        user_id: params.userId,
        layer: MemoryLayer.DAILY_NOTE,
        status: MemoryStatus.DRAFT,
        title,
        content: params.content,
        keywords: params.tags,
        importance_score: 0.6,
      })
      .select('id')
      .single();

    if (error) {
      throw new Error(`创建每日笔记失败: ${error.message}`);
    }

    return (data as any)?.id as string || '';
  }

  /**
   * 获取每日笔记
   */
  async getDailyNotes(userId: string, limit: number = 7): Promise<MemoryEntry[]> {
    const client = getSupabaseClient();

    const { data, error } = await client
      .from('agent_memories')
      .select('*')
      .eq('user_id', userId)
      .eq('layer', MemoryLayer.DAILY_NOTE)
      .order('created_at', { ascending: false })
      .limit(limit);

    if (error) {
      return [];
    }

    return (data || []) as unknown as MemoryEntry[];
  }

  // ==================== 记忆检索 ====================

  /**
   * 检索相关记忆（按层级优先级）
   */
  async retrieveRelevantMemories(params: {
    userId: string;
    query: string;
    limit?: number;
  }): Promise<MemoryEntry[]> {
    const client = getSupabaseClient();
    const { userId, query, limit = 5 } = params;

    // 提取关键词
    const keywords = query
      .replace(/[，。！？；：""''【】（）《》、\n\r\t]/g, ' ')
      .split(/\s+/)
      .filter(word => word.length >= 2)
      .slice(0, 5);

    if (keywords.length === 0) {
      return [];
    }

    // 按优先级检索：SESSION-STATE → WORKING-BUFFER → LONG-TERM → DAILY-NOTES
    const { data, error } = await client
      .from('agent_memories')
      .select('*')
      .eq('user_id', userId)
      .or(keywords.map(kw => 
        `title.ilike.%${kw}%,content.ilike.%${kw}%,summary.ilike.%${kw}%`
      ).join(','))
      .order('importance_score', { ascending: false })
      .limit(limit);

    if (error) {
      return [];
    }

    return (data || []) as unknown as MemoryEntry[];
  }

  // ==================== 记忆清理 ====================

  /**
   * 清理过期的会话状态和工作缓冲区
   */
  async cleanupExpiredMemories(userId: string, daysToKeep: number = 7): Promise<void> {
    const client = getSupabaseClient();
    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - daysToKeep);

    // 清理过期的会话状态
    await client
      .from('agent_memories')
      .delete()
      .eq('user_id', userId)
      .eq('layer', MemoryLayer.SESSION_STATE)
      .lt('updated_at', cutoffDate.toISOString());

    // 清理已蒸馏的工作缓冲区
    await client
      .from('agent_memories')
      .delete()
      .eq('user_id', userId)
      .eq('layer', MemoryLayer.WORKING_BUFFER)
      .eq('status', MemoryStatus.DISTILLED);

    // 清理过期的每日笔记（保留最近30天）
    const notesCutoff = new Date();
    notesCutoff.setDate(notesCutoff.getDate() - 30);
    await client
      .from('agent_memories')
      .delete()
      .eq('user_id', userId)
      .eq('layer', MemoryLayer.DAILY_NOTE)
      .lt('created_at', notesCutoff.toISOString());
  }
}

// 导出工厂函数
export function createMemoryLayerService(headers?: Record<string, string>): MemoryLayerService {
  return new MemoryLayerService(headers);
}

/**
 * 商品图库服务
 * 管理用户上传的商品图片，支持多视角上传和图片整合
 */

import { getSupabaseClient } from '@/storage/database/supabase-client';
import { getTosClient, BUCKET_NAME } from '@/lib/tos-storage';

// ========== 类型定义 ==========

/** 商品图片信息 */
export interface ProductImage {
  view_name: string; // 视角名称：正面、侧面、背面、俯视、细节等
  key: string; // TOS存储key
  url: string; // 签名URL
  uploaded_at: string;
}

/** 商品信息 */
export interface Product {
  id: string;
  user_id: string;
  product_name: string;
  product_description?: string;
  category?: string;
  tags: string[];
  images: ProductImage[];
  primary_image_index: number;
  usage_count: number;
  last_used_at?: string;
  created_at: string;
  updated_at: string;
}

/** 创建商品参数 */
export interface CreateProductParams {
  product_name: string;
  product_description?: string;
  category?: string;
  tags?: string[];
}

/** 上传图片参数 */
export interface UploadImageParams {
  productId: string;
  viewName: string;
  fileContent: Buffer;
  fileName: string;
  contentType: string;
}

/** 整合后的商品图片 */
export interface IntegratedProductImage {
  url: string; // 整合后的图片URL
  width: number;
  height: number;
  viewLabels: string[]; // 各视角标注
}

// ========== 存储路径管理 ==========

/** 商品图库存储路径生成器 */
class ProductStoragePath {
  private userId: string;

  constructor(userId: string) {
    this.userId = userId;
  }

  /** 商品图库根目录 */
  getProductRoot(): string {
    return `users/${this.userId}/products`;
  }

  /** 单个商品目录 */
  getProductDir(productId: string): string {
    return `${this.getProductRoot()}/${productId}`;
  }

  /** 商品图片路径 */
  getProductImagePath(productId: string, fileName: string): string {
    const timestamp = Date.now();
    const ext = fileName.split('.').pop() || 'jpg';
    return `${this.getProductDir(productId)}/images/${timestamp}_${fileName}`;
  }

  /** 整合后的图片路径 */
  getIntegratedImagePath(productId: string): string {
    return `${this.getProductDir(productId)}/integrated_${Date.now()}.jpg`;
  }
}

// ========== 服务类 ==========

class ProductLibraryService {
  /**
   * 创建商品
   */
  async createProduct(
    userId: string,
    params: CreateProductParams
  ): Promise<Product> {
    const client = getSupabaseClient();

    const { data, error } = await client
      .from('product_library')
      .insert({
        user_id: userId,
        product_name: params.product_name,
        product_description: params.product_description,
        category: params.category,
        tags: params.tags || [],
        images: [],
        primary_image_index: 0,
        usage_count: 0,
      })
      .select()
      .single();

    if (error) {
      throw new Error(`创建商品失败: ${error.message}`);
    }

    return data as unknown as Product;
  }

  /**
   * 上传商品图片
   */
  async uploadProductImage(
    userId: string,
    params: UploadImageParams
  ): Promise<ProductImage> {
    const client = getSupabaseClient();
    const tosClient = getTosClient();
    const storagePath = new ProductStoragePath(userId);

    // 获取商品信息
    const { data: product, error: fetchError } = await client
      .from('product_library')
      .select('*')
      .eq('id', params.productId)
      .eq('user_id', userId)
      .single();

    if (fetchError || !product) {
      throw new Error('商品不存在');
    }

    // 上传图片到TOS
    const key = storagePath.getProductImagePath(params.productId, params.fileName);
    await tosClient.putObject({
      bucket: BUCKET_NAME,
      key,
      body: params.fileContent,
      contentType: params.contentType,
    });

    // 生成签名URL（有效期7天）
    const signedUrl = tosClient.getPreSignedUrl({
      bucket: BUCKET_NAME,
      key,
      expires: 7 * 24 * 60 * 60, // 7天
    });

    // 添加图片到商品
    const newImage: ProductImage = {
      view_name: params.viewName,
      key,
      url: signedUrl,
      uploaded_at: new Date().toISOString(),
    };

    const images = [...(product.images as ProductImage[]), newImage];

    await client
      .from('product_library')
      .update({
        images,
        updated_at: new Date().toISOString(),
      })
      .eq('id', params.productId);

    return newImage;
  }

  /**
   * 获取用户的商品列表
   */
  async getProducts(
    userId: string,
    options?: {
      category?: string;
      search?: string;
      limit?: number;
    }
  ): Promise<Product[]> {
    const client = getSupabaseClient();

    let query = client
      .from('product_library')
      .select('*')
      .eq('user_id', userId)
      .order('created_at', { ascending: false });

    if (options?.category) {
      query = query.eq('category', options.category);
    }

    if (options?.search) {
      query = query.ilike('product_name', `%${options.search}%`);
    }

    if (options?.limit) {
      query = query.limit(options.limit);
    }

    const { data, error } = await query;

    if (error) {
      throw new Error(`获取商品列表失败: ${error.message}`);
    }

    // 刷新图片URL
    const products = (data as unknown as Product[]).map(p => this.refreshImageUrls(p));

    return products;
  }

  /**
   * 根据名称查找商品
   */
  async findProductByName(userId: string, productName: string): Promise<Product | null> {
    const client = getSupabaseClient();

    // 支持模糊匹配
    const { data, error } = await client
      .from('product_library')
      .select('*')
      .eq('user_id', userId)
      .ilike('product_name', `%${productName}%`)
      .limit(1)
      .maybeSingle();

    if (error || !data) {
      return null;
    }

    return this.refreshImageUrls(data as unknown as Product);
  }

  /**
   * 根据ID获取商品
   */
  async getProduct(userId: string, productId: string): Promise<Product | null> {
    const client = getSupabaseClient();

    const { data, error } = await client
      .from('product_library')
      .select('*')
      .eq('id', productId)
      .eq('user_id', userId)
      .maybeSingle();

    if (error || !data) {
      return null;
    }

    return this.refreshImageUrls(data as unknown as Product);
  }

  /**
   * 更新商品信息
   */
  async updateProduct(
    userId: string,
    productId: string,
    updates: Partial<Pick<Product, 'product_name' | 'product_description' | 'category' | 'tags' | 'primary_image_index'>>
  ): Promise<Product> {
    const client = getSupabaseClient();

    const { data, error } = await client
      .from('product_library')
      .update({
        ...updates,
        updated_at: new Date().toISOString(),
      })
      .eq('id', productId)
      .eq('user_id', userId)
      .select()
      .single();

    if (error) {
      throw new Error(`更新商品失败: ${error.message}`);
    }

    return this.refreshImageUrls(data as unknown as Product);
  }

  /**
   * 删除商品图片
   */
  async deleteProductImage(
    userId: string,
    productId: string,
    imageKey: string
  ): Promise<void> {
    const client = getSupabaseClient();
    const tosClient = getTosClient();

    // 获取商品
    const product = await this.getProduct(userId, productId);
    if (!product) {
      throw new Error('商品不存在');
    }

    // 删除TOS中的图片
    try {
      await tosClient.deleteObject({
        bucket: BUCKET_NAME,
        key: imageKey,
      });
    } catch (error) {
      console.warn('删除TOS图片失败:', error);
    }

    // 更新商品图片列表
    const images = product.images.filter(img => img.key !== imageKey);
    await client
      .from('product_library')
      .update({
        images,
        updated_at: new Date().toISOString(),
      })
      .eq('id', productId);
  }

  /**
   * 删除商品
   */
  async deleteProduct(userId: string, productId: string): Promise<void> {
    const client = getSupabaseClient();
    const tosClient = getTosClient();

    // 获取商品
    const product = await this.getProduct(userId, productId);
    if (!product) {
      return;
    }

    // 删除TOS中的所有图片
    for (const image of product.images) {
      try {
        await tosClient.deleteObject({
          bucket: BUCKET_NAME,
          key: image.key,
        });
      } catch (error) {
        console.warn('删除TOS图片失败:', error);
      }
    }

    // 删除商品记录
    await client
      .from('product_library')
      .delete()
      .eq('id', productId)
      .eq('user_id', userId);
  }

  /**
   * 记录商品使用
   */
  async recordUsage(userId: string, productId: string): Promise<void> {
    const client = getSupabaseClient();

    await client.rpc('increment_product_usage', { product_id: productId });
  }

  /**
   * 整合多视角商品图片
   * 将多个视角的图片拼接成一张图，并添加标注
   */
  async integrateProductImages(
    userId: string,
    productId: string,
    options?: {
      maxImages?: number; // 最多整合几张图，默认4张
      layout?: 'grid' | 'horizontal' | 'vertical'; // 布局方式
    }
  ): Promise<IntegratedProductImage | null> {
    const product = await this.getProduct(userId, productId);
    if (!product || product.images.length === 0) {
      return null;
    }

    const maxImages = options?.maxImages || 4;
    const layout = options?.layout || 'grid';

    // 选择要整合的图片
    const selectedImages = product.images.slice(0, maxImages);
    if (selectedImages.length === 0) {
      return null;
    }

    // 如果只有一张图，直接返回
    if (selectedImages.length === 1) {
      return {
        url: selectedImages[0].url,
        width: 1024,
        height: 1024,
        viewLabels: [selectedImages[0].view_name],
      };
    }

    // 计算拼接布局
    const { width, height, positions } = this.calculateLayout(
      selectedImages.length,
      layout
    );

    // 构建整合描述（用于提示Seedance理解各视角）
    const viewDescriptions = selectedImages.map((img, index) => {
      const pos = positions[index];
      return `${img.view_name}视角位于图片的${this.getPositionDescription(pos, width, height)}`;
    });

    // 返回整合信息（实际拼接由前端或专门的图片处理服务完成）
    // 这里返回第一张图作为参考，并附带拼接信息
    return {
      url: selectedImages[0].url, // 实际应用中需要拼接处理
      width,
      height,
      viewLabels: selectedImages.map(img => img.view_name),
      // 拼接描述，用于生成Seedance提示词
      integrationInfo: {
        layout,
        positions,
        viewDescriptions,
        originalImages: selectedImages.map(img => ({
          url: img.url,
          viewName: img.view_name,
        })),
      },
    } as IntegratedProductImage & { integrationInfo: unknown };
  }

  /**
   * 为Seedance生成商品参考提示词
   */
  async generateProductPrompt(
    userId: string,
    productName: string
  ): Promise<{
    found: boolean;
    product?: Product;
    referencePrompt?: string;
    imageUrls?: string[];
  }> {
    const product = await this.findProductByName(userId, productName);

    if (!product) {
      return { found: false };
    }

    // 更新使用计数
    await this.recordUsage(userId, product.id);

    // 构建参考提示词
    const imageUrls = product.images.map(img => img.url);
    const viewLabels = product.images.map(img => img.view_name);

    let referencePrompt = `商品: ${product.product_name}`;
    if (product.product_description) {
      referencePrompt += `。${product.product_description}`;
    }
    if (viewLabels.length > 0) {
      referencePrompt += `。商品外观包含: ${viewLabels.join('、')}等视角`;
    }

    return {
      found: true,
      product,
      referencePrompt,
      imageUrls,
    };
  }

  // ========== 私有方法 ==========

  /**
   * 刷新图片URL
   */
  private refreshImageUrls(product: Product): Product {
    const tosClient = getTosClient();

    const refreshedImages = product.images.map(img => ({
      ...img,
      url: tosClient.getPreSignedUrl({
        bucket: BUCKET_NAME,
        key: img.key,
        expires: 7 * 24 * 60 * 60, // 7天
      }),
    }));

    return {
      ...product,
      images: refreshedImages,
    };
  }

  /**
   * 计算拼接布局
   */
  private calculateLayout(
    imageCount: number,
    layout: 'grid' | 'horizontal' | 'vertical'
  ): {
    width: number;
    height: number;
    positions: Array<{ x: number; y: number; w: number; h: number }>;
  } {
    const singleSize = 512;

    if (layout === 'horizontal') {
      return {
        width: singleSize * imageCount,
        height: singleSize,
        positions: Array.from({ length: imageCount }, (_, i) => ({
          x: i * singleSize,
          y: 0,
          w: singleSize,
          h: singleSize,
        })),
      };
    }

    if (layout === 'vertical') {
      return {
        width: singleSize,
        height: singleSize * imageCount,
        positions: Array.from({ length: imageCount }, (_, i) => ({
          x: 0,
          y: i * singleSize,
          w: singleSize,
          h: singleSize,
        })),
      };
    }

    // grid布局
    const cols = Math.ceil(Math.sqrt(imageCount));
    const rows = Math.ceil(imageCount / cols);

    const positions: Array<{ x: number; y: number; w: number; h: number }> = [];
    for (let i = 0; i < imageCount; i++) {
      positions.push({
        x: (i % cols) * singleSize,
        y: Math.floor(i / cols) * singleSize,
        w: singleSize,
        h: singleSize,
      });
    }

    return {
      width: cols * singleSize,
      height: rows * singleSize,
      positions,
    };
  }

  /**
   * 获取位置描述
   */
  private getPositionDescription(
    pos: { x: number; y: number },
    totalWidth: number,
    totalHeight: number
  ): string {
    const horizontal = pos.x < totalWidth / 2 ? '左侧' : pos.x > totalWidth / 2 ? '右侧' : '中间';
    const vertical = pos.y < totalHeight / 2 ? '上部' : pos.y > totalHeight / 2 ? '下部' : '中间';

    if (horizontal === '中间' && vertical === '中间') {
      return '中央';
    }

    return `${vertical}${horizontal}`;
  }
}

