/**
 * 创意小海进化服务
 * 
 * 核心功能：
 * 1. 记录学习（反馈、错误、成功）
 * 2. 知识沉淀
 */

import { getSupabaseClient } from '@/storage/database/supabase-client'

// ========== 类型定义 ==========

export interface LearningRecord {
  id: string
  user_id?: string
  record_type: 'correction' | 'success' | 'error' | 'improvement'
  content: string
  original_content?: string
  feedback?: string
  score?: number
  tags: string[]
  source: 'user_feedback' | 'task_result' | 'self_review'
  status: 'active' | 'applied' | 'archived'
  created_at: string
}

export type RecordType = LearningRecord['record_type']
export type LearningSource = LearningRecord['source']

// ========== 进化服务 ==========

export class XiaohaiEvolutionService {
  // 延迟初始化，避免构建时检查环境变量
  private _supabase: ReturnType<typeof getSupabaseClient> | null = null;

  private get supabase() {
    if (!this._supabase) {
      this._supabase = getSupabaseClient();
    }
    return this._supabase;
  }

  /**
   * 记录学习
   */
  async recordLearning(
    userId: string | null,
    recordType: RecordType,
    content: string,
    options: {
      originalContent?: string
      feedback?: string
      score?: number
      tags?: string[]
      source?: LearningSource
    } = {}
  ): Promise<{ success: boolean; data?: LearningRecord; error?: string }> {
    try {
      const { data, error } = await this.supabase
        .from('xiaohai_learning_records')
        .insert({
          user_id: userId,
          record_type: recordType,
          content,
          original_content: options.originalContent,
          feedback: options.feedback,
          score: options.score,
          tags: options.tags || [],
          source: options.source || 'user_feedback',
          status: 'active'
        })
        .select()
        .single()

      if (error) throw error

      console.log(`[进化服务] 记录学习成功: ${recordType}`, { id: (data as any)?.id, userId })

      return { success: true, data: data as unknown as LearningRecord | undefined }
    } catch (error) {
      console.error('[进化服务] 记录学习失败:', error)
      return { success: false, error: error instanceof Error ? error.message : '记录失败' }
    }
  }

  /**
   * 获取学习记录
   */
  async getLearningRecords(
    userId: string | null,
    query?: string,
    recordType?: RecordType,
    limit: number = 10
  ): Promise<{ success: boolean; data?: LearningRecord[]; error?: string }> {
    try {
      let dbQuery = this.supabase
        .from('xiaohai_learning_records')
        .select('*')
        .eq('status', 'active')
        .order('created_at', { ascending: false })
        .limit(limit * 2)

      if (userId) {
        dbQuery = dbQuery.eq('user_id', userId)
      }

      if (recordType) {
        dbQuery = dbQuery.eq('record_type', recordType)
      }

      const { data, error } = await dbQuery
      if (error) throw error

      // 按关键词匹配排序
      if (query) {
        const queryKeywords = extractKeywords(query)
        const scored = ((data || []) as any[]).map((item: any) => ({
          ...item,
          relevanceScore: (item.tags as string[])?.filter((tag: string) =>
            queryKeywords.some(qk => tag.toLowerCase().includes(qk.toLowerCase()))
          ).length || 0
        }))

        return {
          success: true,
          data: scored
            .sort((a: any, b: any) => b.relevanceScore - a.relevanceScore)
            .slice(0, limit)
        }
      }

      return { success: true, data: (data || []) as unknown as LearningRecord[] }
    } catch (error) {
      console.error('[进化服务] 获取学习记录失败:', error)
      return { success: false, error: error instanceof Error ? error.message : '查询失败' }
    }
  }
}

// ========== 工具函数 ==========

function extractKeywords(text: string): string[] {
  const stopWords = ['的', '是', '在', '了', '和', '与', '或', '不', '要', '会', '能', '可以', '我', '你', '他', '她', '它', '这', '那', '一个', '什么', '怎么', '为什么']
  return text
    .replace(/[^\u4e00-\u9fa5a-zA-Z0-9]/g, ' ')
    .split(/\s+/)
    .filter(word => word.length > 1 && !stopWords.includes(word))
}

/**
 * 创意小海记忆服务
 * 
 * 核心功能：
 * 1. 保存/获取/搜索用户记忆
 * 2. 按关键词相关性排序
 */

import { getSupabaseClient } from '@/storage/database/supabase-client'

// ========== 类型定义 ==========

export type MemoryType = 'general' | 'preference' | 'experience' | 'rule' | 'document'
export type MemorySource = 'user' | 'feedback' | 'error' | 'document'

export interface MemoryRecord {
  id: string
  user_id: string
  content: string
  memory_type: MemoryType
  keywords: string[]
  source: MemorySource
  metadata?: Record<string, any>
  created_at: string
  updated_at: string
}

// ========== 记忆服务 ==========

export class XiaohaiMemoryService {
  // 延迟初始化，避免构建时检查环境变量
  private _supabase: ReturnType<typeof getSupabaseClient> | null = null;

  private get supabase() {
    if (!this._supabase) {
      this._supabase = getSupabaseClient();
    }
    return this._supabase;
  }

  /**
   * 保存记忆
   */
  async saveMemory(
    userId: string,
    content: string,
    memoryType: MemoryType,
    keywords: string[],
    options: { source?: MemorySource; metadata?: Record<string, any> } = {}
  ): Promise<{ success: boolean; data?: MemoryRecord; error?: string }> {
    try {
      const { data, error } = await this.supabase
        .from('xiaohai_user_memories')
        .insert({
          user_id: userId,
          content,
          memory_type: memoryType,
          keywords,
          source: options.source || 'user',
          metadata: options.metadata || {}
        })
        .select()
        .single()

      if (error) throw error

      console.log(`[记忆服务] 保存记忆成功: ${(data as any)?.id}, type=${memoryType}`)

      if (!data) {
        throw new Error('保存记忆失败：未返回数据')
      }

      return { success: true, data: data as unknown as MemoryRecord }
    } catch (error) {
      console.error('[记忆服务] 保存记忆失败:', error)
      return { success: false, error: error instanceof Error ? error.message : '保存失败' }
    }
  }

  /**
   * 获取记忆（按关键词相关性排序）
   */
  async getMemories(
    userId: string,
    query: string,
    memoryType?: string,
    limit: number = 10
  ): Promise<{ success: boolean; data?: MemoryRecord[]; error?: string }> {
    try {
      const queryKeywords = extractKeywords(query)

      // 构建查询
      let dbQuery = this.supabase
        .from('xiaohai_user_memories')
        .select('*')
        .eq('user_id', userId)
        .limit(50)

      if (memoryType && memoryType !== 'all') {
        dbQuery = dbQuery.eq('memory_type', memoryType)
      }

      const { data, error } = await dbQuery
      if (error) throw error

      // 按关键词命中数排序
      const scored = ((data || []) as any[]).map((item: any) => {
        const hits = (item.keywords as string[])?.filter((k: string) =>
          queryKeywords.some(qk => 
            k.toLowerCase().includes(qk.toLowerCase()) ||
            qk.toLowerCase().includes(k.toLowerCase())
          )
        ).length || 0

        return { ...item, relevanceScore: hits }
      })

      // 按关键词命中数排序，然后返回所有（没有命中也返回最近的）
      const result = scored
        .sort((a: any, b: any) => b.relevanceScore - a.relevanceScore)
        .slice(0, limit) as MemoryRecord[]

      console.log(`[记忆服务] 获取记忆: query="${query}", found=${result.length}`)

      return { success: true, data: result }
    } catch (error) {
      console.error('[记忆服务] 获取记忆失败:', error)
      return { success: false, error: error instanceof Error ? error.message : '查询失败' }
    }
  }

  /**
   * 搜索记忆
   */
  async searchMemories(
    userId: string,
    keyword: string,
    memoryType?: string
  ): Promise<{ success: boolean; data?: MemoryRecord[]; error?: string }> {
    try {
      let dbQuery = this.supabase
        .from('xiaohai_user_memories')
        .select('*')
        .eq('user_id', userId)
        .textSearch('content', keyword)

      if (memoryType) {
        dbQuery = dbQuery.eq('memory_type', memoryType)
      }

      const { data, error } = await dbQuery
      if (error) throw error

      console.log(`[记忆服务] 搜索记忆: keyword="${keyword}", found=${(data || []).length}`)

      return { success: true, data: (data || []) as unknown as MemoryRecord[] }
    } catch (error) {
      console.error('[记忆服务] 搜索记忆失败:', error)
      return { success: false, error: error instanceof Error ? error.message : '搜索失败' }
    }
  }

  /**
   * 从反馈学习
   */
  async learnFromFeedback(
    userId: string,
    originalResponse: string,
    userFeedback: string,
    isCorrection: boolean
  ): Promise<{ success: boolean; error?: string }> {
    try {
      const keywords = extractKeywords(userFeedback)

      const content = isCorrection
        ? `用户纠正: ${userFeedback} | 原回答: ${originalResponse}`
        : `用户补充: ${userFeedback} | 原回答: ${originalResponse}`

      await this.saveMemory(userId, content, 'experience', keywords, { source: 'feedback' })

      console.log(`[记忆服务] 反馈学习: isCorrection=${isCorrection}`)

      return { success: true }
    } catch (error) {
      console.error('[记忆服务] 反馈学习失败:', error)
      return { success: false, error: error instanceof Error ? error.message : '学习失败' }
    }
  }

  /**
   * 删除记忆
   */
  async deleteMemory(
    memoryId: string,
    userId: string
  ): Promise<{ success: boolean; error?: string }> {
    try {
      const { error } = await this.supabase
        .from('xiaohai_user_memories')
        .delete()
        .eq('id', memoryId)
        .eq('user_id', userId)

      if (error) throw error

      console.log(`[记忆服务] 删除记忆: ${memoryId}`)

      return { success: true }
    } catch (error) {
      console.error('[记忆服务] 删除记忆失败:', error)
      return { success: false, error: error instanceof Error ? error.message : '删除失败' }
    }
  }
}

// ========== 工具函数 ==========

function extractKeywords(text: string): string[] {
  const stopWords = ['的', '是', '在', '了', '和', '与', '或', '不', '要', '会', '能', '可以', '我', '你', '他', '她', '它', '这', '那', '一个', '什么', '怎么', '为什么']
  return text
    .replace(/[^\u4e00-\u9fa5a-zA-Z0-9]/g, ' ')
    .split(/\s+/)
    .filter(word => word.length > 1 && !stopWords.includes(word))
}

